    private function buildUserContext($user, $token)
        {
            $useraccess = $this->checkeditaccess($token);
        
            return [
                'user_role' => $useraccess['role'] ?? '',
                'logged_in_user' => [
                    'name' => $user->name ?? '',
                    'email' => $user->email ?? '',
                    'mobile' => $user->mobile ?? '',
                    'business_name' => $user->business_name ?? ''
                ]
            ];
        }

    public function weddingguidedashboardnew(Request $request)
        {
                $token = $request->header('Authorization');
                $user = $this->getuser($token);
                
                if($user) 
                {
                    $user_details = ['name' => $user->name,'email' => $user->email,'mobile' => $user->mobile,'business_name' => $user->business_name];
                    
                    $useraccess = $this->checkeditaccess($token);
                    $user_role = $useraccess['role'];
                    $user_access_array = $useraccess['access_array'];
                    
                    $headingmsg = translateLongText('This tool will help you to generate the model budget, minutes of meeting, generate requirement, 
                    generate quote, plan itenary, update payment and many more. A email wil be sent to client with their login credential for them to access wedding guide.');
        
                    $search = $request->search;
                    $paginate = $request->paginate;
                    
                    if(!empty($search))
                    {
                        $allowsearch = true;
                    }
                    else
                    {
                        $allowsearch = false;
                    }
        
                    $compare_team = false;
                    $compare_user = false;
        
                    if($user_role == 'admin' || $user_role == 'partner admin')
                    {
                        $users = User::where('team_id',$user->id)->select('id')->get()->pluck('id')->toArray();
                        array_push($users, $user->id);
                        $compare_user = true;
        
                        $usersid =  $user->id;
        
                    }
                    else if($user_role == 'sub admin')
                    {
                        $users = User::where('team_id',$user->team_id)->select('id')->get()->pluck('id')->toArray();
                        array_push($users, $user->team_id);
                        $compare_team = true;
        
                        $usersid =  $user->team_id;
                    }
                    else if($user_role == 'team member')
                    {
                        $users = User::where('id',$user->id)->select('id')->get()->pluck('id')->toArray();
                        //array_push($users, $user->id);
                        array_push($users, $user->id);
                        $compare_team = true;
        
                        $usersid =  $user->id;
                    }
                    else
                    {
                        return response()->json([
                            'message' => uiFast('User do not have access'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                            'headingmsg' => "",
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 401);
                    }
                    
        
                    if($user_role == 'admin' || $user_role == 'partner admin' || $user_role == 'sub admin')
                    { 
                        $clients = Client::select('clients.id','clients.main_id', 'clients.name', 'clients.email', 'clients.mobile', 'partner_name', 'partner_email', 'location', 'budget', 'guests', 'clients.remarks',
                        'clients.bride_name','clients.bride_mobile','clients.groom_name','clients.groom_mobile',
                            'u1.id as admin_userid','u1.name as admin_username','u2.id as team_userid','u2.name as team_username',
                            DB::raw('(CASE 
