    private function buildClientApiResponse($client)
        {
            $data = $client->toArray();
        
            // Name
            $data['name_value']   = $client->name ?? null;
            $data['name_display'] = $client->name
                ? transliterateTextKeepNumbers($client->name)
                : '-';
        
            // Partner name
            $data['partner_name_value']   = $client->partner_name ?? null;
            $data['partner_name_display'] = $client->partner_name
                ? transliterateTextKeepNumbers($client->partner_name)
                : '-';
        
            // Bride name
            $data['bride_name_value']   = $client->bride_name ?? null;
            $data['bride_name_display'] = $client->bride_name
                ? transliterateTextKeepNumbers($client->bride_name)
                : '-';
        
            // Groom name
            $data['groom_name_value']   = $client->groom_name ?? null;
            $data['groom_name_display'] = $client->groom_name
                ? transliterateTextKeepNumbers($client->groom_name)
                : '-';
        
            // Location → direct translate (no value/display split)
            if (!empty($client->location)) {
                $data['location'] = translateAddressSafe($client->location);
            }
        
            // ❌ Remove raw fields from API
            unset(
                $data['name'],
                $data['partner_name'],
                $data['bride_name'],
                $data['groom_name']
            );
        
            return $data;
        } 
