    public function removeguideclient(Request $request)
        {
        $token = $request->header('Authorization');
        $user = $this->getuser($token);
        
        if($user) 
        {
            $user_details = ['name' => $user->name,'email' => $user->email,'mobile' => $user->mobile,'business_name' => $user->business_name];
            
            $useraccess = $this->checkeditaccess($token);
            $user_role = $useraccess['role'];
            $user_access_array = $useraccess['access_array'];
            
            // Validations
            $rules = [
                'item_id'     => 'required|numeric'
            ];
            
            $validator = Validator::make($request->all(), $rules);

            if ($validator->fails()) 
            {
                $errors = $validator->errors()->toArray();

                // 🌐 Translate each validation message
                foreach ($errors as $field => &$messages) {
                    foreach ($messages as &$msg) {
                        $msg = t($msg);
                    }
                }
                
                return response()->json([
                    'message' => $errors,
                ], 422);
            } 
            else 
            {
                $item_id = $request->item_id;
                $compare_team = false;
                $compare_user = false;

                if($user_role == 'admin' || $user_role == 'partner admin')
                {
                    $users = User::where('team_id',$user->id)->select('id')->get()->pluck('id')->toArray();
                    array_push($users, $user->id);
                    $compare_user = true;
                }
                else if($user_role == 'sub admin')
                {
                    $users = User::where('team_id',$user->team_id)->select('id')->get()->pluck('id')->toArray();
                    array_push($users, $user->team_id);
                    $compare_team = true;
                }
                else if($user_role == 'team member')
                {
                    $users = User::where('id',$user->id)->select('id')->get()->pluck('id')->toArray();
                    array_push($users, $user->id);
                    $compare_team = true;
                }
                else
                {
                    return response()->json([
                        'message' => uiFast('User do not have access'),
                        'status' => '0',
                        'data' => [],
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                        'base_url' => 'https://planawedding.in/storage/',
                    ], 401);
                }

                $client = Client::where('id',$item_id)
                ->when($compare_team, function ($query) use ($users) {
                    $query->where(function($q) use ($users){
                        $q->whereIn('team_id',$users);
                    });
                })
                ->when($compare_user, function ($query) use ($users) {
                    $query->where(function($q) use ($users){
                        $q->whereIn('user_id',$users);
                    });
                })
                ->first();

                if($client)
                {



                    foreach ($client->loginUsers as $loginUser) {
                        // Step 1: Get all event IDs linked to this login user
                        $eventIds = \DB::table('client_events')
                            ->where('family_login_id', $loginUser->id)
                            ->orWhere('groom_id', $loginUser->id)
                            ->orWhere('bride_id', $loginUser->id)
                            ->pluck('id');

                        if ($eventIds->count() > 0) {
                            // Step 2: Get all guest IDs linked to those events
                            $guestIds = \DB::table('guests')
                                ->whereIn('category_id', $eventIds)
                                ->pluck('id');

                            if ($guestIds->count() > 0) {
                                // Step 3: Delete send_guest_invitaion
                                \DB::table('send_guest_invitaion')
                                    ->whereIn('guest_id', $guestIds)
                                    ->delete();

                                // Step 4: Delete user_app_tokens
                                \DB::table('user_app_tokens')
                                    ->whereIn('guest_actual_id', $guestIds)
                                    ->delete();

                                // Step 5: Delete guests
                                \DB::table('guests')
                                    ->whereIn('id', $guestIds)
                                    ->delete();
                            }

                            // Step 6: Delete events
                            \DB::table('client_events')
                                ->whereIn('id', $eventIds)
                                ->delete();
                        }

                        // Step 7: Delete client_profile linked to this login user
                        \DB::table('client_profile')
                            ->where('groom_id', $loginUser->id)
                            ->orWhere('bride_id', $loginUser->id)
                            ->orWhere('family_id', $loginUser->id)
                            ->delete();

                        // Step 8: Delete login user
                        $loginUser->delete();
                    }

                    // Step 9: Delete login_datarecord_app entries tied to this client
                    \DB::table('login_datarecord_app')
                        ->where('client_id', $client->id)
                        ->delete();

                    // Step 10: Delete user_appfcm_tokens entries tied to this client
                    \DB::table('user_appfcm_tokens')
                        ->where('user_id', $client->id)
                        ->delete();

                    $client->delete();
                    return response()->json([
                        'message' => uiFast('Client Deleted'),
                        'status' => '1',
                        'data' => [],
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                        'base_url' => 'https://planawedding.in/storage/',
                    ], 200);
                }
                else
                {
                    return response()->json([
                        'message' => uiFast('Client Not Found'),
                        'status' => '0',
                        'data' => [],
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                        'base_url' => 'https://planawedding.in/storage/',
                    ], 200);
                }
            }
        } 
        else 
        {
            return response()->json([
                'message' => uiFast('User not found'),
                'status' => '0',
                'data' => [],
                'user_role' => "",
                'logged_in_user' => [],
                'base_url' => 'https://planawedding.in/storage/',
            ], 401);
        }
    }
