    public function guidebudgetdetails(Request $request)
        {
            $token = $request->header('Authorization');
            $user  = $this->getuser($token);
        
            if (!$user) {
                return response()->json([
                    'message' => uiFast('User not found'),
                    'status'  => '0',
                    'data'    => [],
                ], 401);
            }
        
            $pageheading = "Enter minutes of meeting between you and the customer, the same will be visible to your client in customer login";
            $boxheading  = "Select all the checkboxes below and click Proceed to generate Minutes of Meeting";
        
            $user_details = [
                'name'          => $user->name,
                'email'         => $user->email,
                'mobile'        => $user->mobile,
                'business_name' => $user->business_name
            ];
        
            $useraccess = $this->checkeditaccess($token);
            $user_role  = $useraccess['role'];
        
            $clientid = $request->clientid;
        
            if (empty($clientid)) {
                return response()->json([
                    'message'        => uiFast('Unable to find client id'),
                    'status'         => '0',
                    'pageheading'    => uiFast($pageheading),
                    'boxheading'     => '',
                    'default_values' => '',
                    'data'           => [],
                    'user_role'      => $user_role,
                    'logged_in_user' => $user_details,
                ], 503);
            }
        
            /* ===============================
               DEFAULT VALUES
            =============================== */
        
            $default_values = [
                'Venue' => [
                    'idvalue'   => '607',
                    'displayas' => 'Venue',
                    'subitems'  => [],
                ],
                'Catering' => [
                    'idvalue'   => '592',
                    'displayas' => 'Catering',
                    'subitems'  => [
                        'Buffet Dinner for Reception',
                        'Breakfast on Muhurat Day',
                        'Coffee / Tea & Snacks',
                        'Lunch on Muhurat Day'
                    ],
                ],
                'Decorations' => [
                    'idvalue'   => '608',
                    'displayas' => 'Decorations',
                    'subitems'  => [
                        'Mantap Decorations',
                        'Reception Decorations',
                        'Entrance Name Board',
                        'Walk Path Decor'
                    ],
                ],
                'Photo & videography' => [
                    'idvalue'   => '610',
                    'displayas' => 'Photo & videography',
                    'subitems'  => [
                        'Traditional Photo',
                        'Traditional Video',
                        'Candid Photo',
                        'Cinematic Video'
                    ],
                ],
                'Other essentials' => [
                    'idvalue'   => '611',
                    'displayas' => 'Other essentials',
                    'subitems'  => [
                        'Tent house',
                        'Bridal Makeup',
                        'Nadaswaram',
                        'Sound',
                        'Light'
                    ],
                ],
            ];
        
            /* ===============================
               SPLIT & TRANSLATE DEFAULT VALUES
            =============================== */
        
            foreach ($default_values as &$item) {
        
                $item['displayas_value']        = $item['displayas'];
                $item['displayas_display_text'] = uiFast($item['displayas']);
                unset($item['displayas']);
        
                if (!empty($item['subitems'])) {
                    $subs = [];
                    foreach ($item['subitems'] as $s) {
                        $subs[] = [
                            'value'        => $s,
                            'display_text' => uiFast($s),
                        ];
                    }
                    $item['subitems'] = $subs;
                }
            }
        
            /* ===============================
               CHECK BUDGET
            =============================== */
        
            $budget = Budget::where('client_id', $clientid)->latest()->first();
        
            if (!$budget) {
                return response()->json([
                    'message'        => uiFast('Show Default Budget List data and not to show mom'),
                    'status'         => '1',
                    'pageheading'    => uiFast($pageheading),
                    'boxheading'     => uiFast($boxheading),
                    'default_values' => $default_values,
                    'data'           => [],
                    'user_role'      => $user_role,
                    'logged_in_user' => $user_details,
                ], 200);
            }
        
            /* ===============================
               BUDGET LISTING
            =============================== */
        
            $budgetlisting = Budget::select(
                    'budgets.*',
                    'budgetmoms.id as mom_id',
                    'budgetmoms.budget_id as mom_budget_id',
                    'budgetmoms.name as mom_name',
                    'budgetmoms.new_momnotes as mom_remarks',
                    'budgetmoms.momnotes as mom_old_remarks'
                )
                ->leftJoin('budgetmoms', 'budgets.id', '=', 'budgetmoms.budget_id')
                ->where('budgets.client_id', $clientid)
                ->orderBy('budgets.item_order', 'asc')
                ->get();
        
            foreach ($budgetlisting as &$b) {
        
                // name
                $b->name_value        = $b->name;
                $b->name_display_text = uiFast($b->name);
                unset($b->name);
        
                // estimated_item & actual_item
                foreach (['estimated_item', 'actual_item'] as $key) {
                    if (!empty($b->$key)) {
                        $items = json_decode($b->$key, true);
                        if (is_array($items)) {
                            foreach ($items as &$i) {
                                if (!empty($i['particular'])) {
                                    $i['particular_value']        = $i['particular'];
                                    $i['particular_display_text'] =
                                        transliterateTextKeepNumbers($i['particular']);
                                    unset($i['particular']);
                                }
                            }
                        }
                        $b->$key = $items;
                    }
                }
        
                // mom_name
                if (!empty($b->mom_name)) {
                    $b->mom_name_value        = $b->mom_name;
                    $b->mom_name_display_text = uiFast($b->mom_name);
                    unset($b->mom_name);
                }
        
                // mom remarks
                foreach (['mom_remarks', 'mom_old_remarks'] as $rk) {
                    if (!empty($b->$rk)) {
                        $remarks = json_decode($b->$rk, true);
                        if (is_array($remarks)) {
                            foreach ($remarks as &$r) {
                                if (!empty($r['remarkcolumn'])) {
                                    $r['remarkcolumn_value']        = $r['remarkcolumn'];
                                    $r['remarkcolumn_display_text'] =
                                        transliterateTextKeepNumbers($r['remarkcolumn']);
                                    unset($r['remarkcolumn']);
                                }
                            }
                        }
                        $b->$rk = $remarks;
                    }
                }
            }
        
            return response()->json([
                'message'        => 'Show directly Mom details and if edit then show budget checkboxes',
                'status'         => '1',
                'pageheading'    => uiFast($pageheading),
                'boxheading'     => uiFast($boxheading),
                'default_values' => $default_values,
                'budgetlisting'  => $budgetlisting,
                'user_role'      => $user_role,
                'logged_in_user' => $user_details,
            ], 200);
        } 
        
        
    private function calculationprice($themename,$estimatedprice)
        {
             if($themename == 'Decorations')
            {
                $value =  ( (20 / 100) * $estimatedprice);
               return $value;
            }
            else if($themename == 'Catering')
            {
                $value =  ( (35 / 100) * $estimatedprice);
               return $value;
            }
            else if($themename == 'Venue')
            {
                $value =  ( (15 / 100) * $estimatedprice);
               return $value;
            }
            else if($themename == 'Photo & videography')
            {
                $value =  ( (15 / 100) * $estimatedprice);
               return $value;
            }
            else if($themename == 'Other essentials')
            {
                $value =  ( (15 / 100) * $estimatedprice);
                return $value;
            }
            else
            {
                $value = 0;
                return $value;
            }
             
        }
