                            }
                        $item_json = json_encode($items);
                        return $item_json; 
                    }
                else if($themename == 'Photo & videography')
                    {
                        $calctime = time();
                        $listitemsadd = $photovideo_name;
                        $listitems1 = explode(",",$listitemsadd);
                        
                        $newelements = array_map(function($x){ return $x . '^123'; }, $listitems1);
                        $listitems = implode(',', $newelements); 
                        $listitems = substr($listitems, 0, -1); 
                        $listitems = explode(",",$listitems);
                        $itemCount = count($listitems);
                        $items = array();
                        $j = 0;
                        $k = 0;
                        if(count(array_filter($listitems)) != 0)
                            {
                                for($i=1; $i<= $itemCount; $i++)
                                    {
                                    
                                        $k++;
                                        
                                        $oneitem = $listitems[$j];
                                        $oneitem = explode("^",$oneitem);

                                        $items[$i]['particular'] = $oneitem[0];
                                        $items[$i]['time'] = $oneitem[1];
                                        $items[$i]['itemno'] = $k;
                                        
                                    
                                        $j++;  
                                    }
                            }
                        $item_json = json_encode($items);
                        return $item_json;  
                    }
                else if($themename == 'Other essentials')
                    {
                        $calctime = time();
                        $listitemsadd = $other_name;
                        $listitems1 = explode(",",$listitemsadd);
                        
                        $newelements = array_map(function($x){ return $x . '^123'; }, $listitems1);
                        $listitems = implode(',', $newelements); 
                        $listitems = substr($listitems, 0, -1); 
                        $listitems = explode(",",$listitems);
                        $itemCount = count($listitems);
                        $items = array();
                        $j = 0;
                        $k = 0;
                        if(count(array_filter($listitems)) != 0)
                            {
                                for($i=1; $i<= $itemCount; $i++)
                                {
                                
                                    $k++;
                                    
                                    $oneitem = $listitems[$j];
                                    $oneitem = explode("^",$oneitem);

                                    $items[$i]['particular'] = $oneitem[0];
                                    $items[$i]['time'] = $oneitem[1];
                                    $items[$i]['itemno'] = $k; 
                                    $j++;  
                                }
                            
                            }
                        $item_json = json_encode($items);
                        return $item_json;  
                    }
            }
    private function itemorder($themename)
        {
            if($themename == 'Venue')
                {
                    $value =  "1";
                    return $value;
                }
            else if($themename == 'Catering')
                {
                    $value =  "2";
                    return $value;
                }
            else if($themename == 'Decorations')
                {
                    $value =  "3";
                    return $value;
                }
            else if($themename == 'Photo & videography')
                {
                    $value =  "4";
                    return $value;
                }
            else if($themename == 'Other essentials')
                {
                    $value =  "5";
                    return $value;
                }
            else
                {
                    $value = 0;
                    return $value;
                }
        } 
    public function guidenewsavebudgetitems(Request $request)
        {
            $token = $request->header('Authorization');
            $user = $this->getuser($token);
        
            if ($user) {
                $user_details = [
                    'name' => $user->name,
                    'email' => $user->email,
                    'mobile' => $user->mobile,
                    'business_name' => $user->business_name
                ];
        
                $useraccess = $this->checkeditaccess($token);
                $user_role = $useraccess['role'];
                $user_access_array = $useraccess['access_array'];
        
                $rules = [
                    'clientid'  => 'required|numeric',
                    'theme_ids' => 'required',
                ];
        
                $validator = Validator::make($request->all(), $rules);
        
                if ($validator->fails()) {
        
                    $errors = $validator->errors()->toArray();
                    foreach ($errors as &$msgs) {
                        foreach ($msgs as &$m) {
                            $m = t($m);
                        }
                    }
        
                    return response()->json([
                        'message' => $errors,
                    ], 422);
                } else {
        
                    if ($user->team_id == null || $user->team_id == '') {
                        $usermainid = $user->id;
                        $userteamid = null;
                    } else if ($user->is_partner == 2 && $user->is_admin == 1) {
                        $usermainid = $user->team_id;
                        $userteamid = null;
                    } else {
                        $usermainid = $user->team_id;
                        $userteamid = $user->id;
                    }
        
                    $client_id = $request->clientid;
                    $items_added = explode(",", $request->theme_ids);
        
                    if ($userteamid == null) {
                        $client = Client::where('id', $client_id)
                            ->where('user_id', $usermainid)
                            ->latest()->first();
                    } else {
                        $client = Client::where('id', $client_id)
                            ->where('user_id', $usermainid)
                            ->where('team_id', $userteamid)
                            ->latest()->first();
                    }
        
                    $totalbudget = $client->budget ?? 0;
        
                    $full_budget_item = Budget::where('client_id', $client_id)->get();
                    $count_item = count($full_budget_item);
        
                    $cater_name      = $request->catering_subitems;
                    $decor_name      = $request->decoration_subitems;
                    $photovideo_name = $request->photovideo_subitems;
                    $other_name      = $request->otheressential_subitems;
        
                    foreach ($items_added as $item) {
                        $theme = Theme::find($item);
        
                        if ($theme) {
                            $budget_item = Budget::where('client_id', $client_id)
                                ->where('theme_id', $theme->id)
                                ->latest()->first();
        
                            if (!$budget_item) {
                                $budget_item = new Budget();
                                $budget_item->client_id = $client_id;
                                $budget_item->theme_id = $theme->id;
                                $budget_item->from_yoee = 1;
                            }
        
                            $budget_item->name = $theme->theme_name;
                            $budget_item->estimated_price =
                                $this->calculationprice($theme->theme_name, $totalbudget);
        
                            $budget_item->estimated_item =
                                $this->estimateditemnew(
                                    $theme->theme_name,
                                    $cater_name,
                                    $decor_name,
                                    $photovideo_name,
                                    $other_name
                                );
        
                            $budget_item->actual_item = $budget_item->estimated_item;
                            $budget_item->actual_price = 0;
                            $budget_item->item_order =
                                $this->itemorder($theme->theme_name);
        
                            $budget_item->save();
                        }
                    }
        
                    // 🔥 TRANSLATE RESPONSE DATA ONLY
                    foreach ($full_budget_item as &$budget) {
        
                        // name split
                        $budget->name_value = $budget->name;
                        $budget->name_display_text = uiFast($budget->name);
                        unset($budget->name);
        
                        // estimated_item
                        if (!empty($budget->estimated_item)) {
                            $items = json_decode($budget->estimated_item, true);
        
                            if (is_array($items)) {
                                foreach ($items as &$i) {
                                    if (!empty($i['particular'])) {
                                        $i['particular_value'] = $i['particular'];
                                        $i['particular_display_text'] =
                                            transliterateTextKeepNumbers($i['particular']);
                                        unset($i['particular']);
                                    }
                                }
                            }
                            $budget->estimated_item = $items;
                        }
        
                        // actual_item
                        if (!empty($budget->actual_item)) {
                            $items = json_decode($budget->actual_item, true);
        
                            if (is_array($items)) {
                                foreach ($items as &$i) {
                                    if (!empty($i['particular'])) {
                                        $i['particular_value'] = $i['particular'];
                                        $i['particular_display_text'] =
                                            transliterateTextKeepNumbers($i['particular']);
                                        unset($i['particular']);
                                    }
                                }
                            }
                            $budget->actual_item = $items;
                        }
                    }
        
                    return response()->json([
                        'message' => uiFast('Details updated'),
                        'status' => '1',
                        'data' => $full_budget_item,
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            } else {
                return response()->json([
                    'message' => uiFast('User not found'),
                    'status' => '0',
                    'data' => [],
                    'user_role' => "",
                    'logged_in_user' => [],
                ], 401);
            }
        }
