            ], 401);
        }
    public function guidenewsavemom(Request $request)
        {
            $token = $request->header('Authorization');
            $user = $this->getuser($token);
        
            if (!$user) {
                return response()->json([
                    'message' => uiFast('User not found'),
                    'status'  => '0'
                ], 401);
            }
        
            $rules = [
                'id'       => 'required|numeric',
                'clientid' => 'required',
                'momname'  => 'required',
            ];
        
            $validator = Validator::make($request->all(), $rules);
        
            if ($validator->fails()) {
        
                $errors = $validator->errors()->toArray();
                foreach ($errors as &$msgs) {
                    foreach ($msgs as &$m) {
                        $m = t($m);
                    }
                }
        
                return response()->json(['message' => $errors], 422);
            }
        
            $item = Budget::where('id', $request->id)
                ->where('client_id', $request->clientid)
                ->latest()
                ->first();
        
            if (!$item) {
                return response()->json([
                    'message' => uiFast('Budget item not found'),
                    'status'  => '0'
                ]);
            }
        
            /* ================= ITEM NAME FIX ================= */
        
            $itemname = $item->name;
        
            if ($itemname == "Photo & videography") {
                $itemchosen = "Photovideography";
            } elseif ($itemname == "Other essentials") {
                $itemchosen = "Otheressentials";
            } else {
                $itemchosen = $itemname;
            }
        
            $budgetid = $item->id;
        
            /* ================= FETCH MOM ================= */
        
            $budgetmom = Budgetmom::where('budget_id', $budgetid)
                ->where('client_id', $request->clientid)
                ->latest()
                ->first();
        
            /* ================= DATE & VALUE ================= */
        
            $todaytime = date('d/m/Y H:i:s');
            $momText   = trim($request->momname);
        
            /* ========================================================= */
            /* ✅ SAFE SAVE LOGIC (NO STRING MANIPULATION) */
            /* ========================================================= */
        
            if ($budgetmom) {
        
                // Decode existing notes
                $existingNotes = json_decode($budgetmom->new_momnotes, true);
        
                if (!is_array($existingNotes)) {
                    $existingNotes = [];
                }
        
            } else {
        
                // Create new MOM row
                $budgetmom = new Budgetmom();
                $budgetmom->client_id = $request->clientid;
                $budgetmom->budget_id = $budgetid;
                $budgetmom->name      = $itemchosen;
        
                $existingNotes = [];
            }
        
            /* ================= NEXT REMARK NUMBER ================= */
        
            if (!empty($existingNotes)) {
        
                $keys = array_keys($existingNotes);
                $numericKeys = array_filter($keys, 'is_numeric');
        
                $nextRemarkNo = !empty($numericKeys)
                    ? max($numericKeys) + 1
                    : 10000;
        
            } else {
                $nextRemarkNo = 10000;
            }
        
            /* ================= APPEND NEW NOTE ================= */
        
            $existingNotes[$nextRemarkNo] = [
                'remarkno'     => (string)$nextRemarkNo,
                'remarkcolumn' => $momText,
                'datedtime'    => $todaytime,
            ];
        
            /* ================= SAVE BACK ================= */
        
            $budgetmom->new_momnotes = json_encode($existingNotes);
        
            if (!$budgetmom->save()) {
                return response()->json([
                    'message' => uiFast('Issues in Saving Item'),
                    'status'  => '0'
                ]);
            }
        
            /* ========================================================= */
            /* 🌐 TRANSLATION (DISPLAY ONLY – DB SAFE) */
            /* ========================================================= */
        
            $translatedMomNotes = [];
        
            foreach ($existingNotes as $k => $r) {
        
                $translatedMomNotes[$k] = [
                    'remarkno' => $r['remarkno'] ?? '',
                    'remarkcolumn_value' => $r['remarkcolumn'] ?? '',
        
                    // 👇 Only for UI
                    'remarkcolumn_display_text' =>
                        !empty($r['remarkcolumn'])
                            ? transliterateTextKeepNumbers($r['remarkcolumn'])
                            : '',
        
                    'datedtime' => $r['datedtime'] ?? '',
                ];
            }
        
            return response()->json([
                'message'  => uiFast('Item details updated.'),
                'status'   => '1',
                'data'     => $translatedMomNotes,
                'momnotes' => $translatedMomNotes,
            ], 201);
        }


    public function weddingguidegetquotations_1(Request $request)
        {
            $token = $request->header('Authorization');
            $user  = $this->getuser($token);
        
            if (!$user) {
                return response()->json([
                    'message' => uiFast('User not found'),
                    'status'  => '0',
                    'data'    => [],
                    'user_role' => "",
                    'logged_in_user' => [],
                ], 401);
            }
        
            $user_details = [
                'name' => $user->name,
                'email' => $user->email,
                'mobile' => $user->mobile,
                'business_name' => $user->business_name
            ];
        
            $useraccess = $this->checkeditaccess($token);
            $user_role  = $useraccess['role'];
        
            $validator = Validator::make($request->all(), [
                'clientid' => 'required|numeric',
            ]);
        
            if ($validator->fails()) {
                $errors = $validator->errors()->toArray();
                foreach ($errors as &$msgs) {
                    foreach ($msgs as &$m) {
                        $m = t($m);
                    }
                }
                return response()->json(['message' => $errors], 422);
            }
        
            $clientid = $request->clientid;
            $item_id  = $request->id;
            $search   = $request->search;
            $allowsearch = !empty($search);
        
            /* ================= USER SCOPE ================= */
            $users = [];
        
            if ($user_role == 'admin' || $user_role == 'partner admin') {
                $users = User::where('team_id', $user->id)->pluck('id')->toArray();
                $users[] = $user->id;
            } elseif ($user_role == 'sub admin') {
                $users = User::where('team_id', $user->team_id)->pluck('id')->toArray();
                $users[] = $user->team_id;
            } elseif ($user_role == 'team member') {
                $users[] = $user->id;
            } else {
                return response()->json([
                    'message' => uiFast('User do not have access'),
                    'status'  => '0',
                    'data'    => [],
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                ], 401);
            }
        
            /* ================= QUERY ================= */
        
            $query = Epquotation::select([
                'epquotations.id','epquotations.client_id','epquotations.event_date',
                'epquotations.event_type','epquotations.inserted_at','epquotations.received_status',
                'epquotations.quotationid','epquotations.userid','epquotations.event_location',
                'epquotations.quotation_number','epquotations.name','epquotations.order_confirm',
                'epquotations.booking_from','epquotations.pdf',
                'payorders.quotedate','quotations.accepted_amount',
                'users.name as genname',
                DB::raw("TIMESTAMPDIFF(HOUR,epquotations.inserted_at,now()) as hours"),
                DB::raw('(CASE 
                    WHEN epquotations.booking_from = "eventplanner" THEN "Self"
                    ELSE "Plan a Wedding"
                END) AS source')
            ])
            ->leftJoin("payorders","epquotations.quotationid","=","payorders.quoteid")
            ->leftJoin("quotations","epquotations.quotationid","=","quotations.id")
            ->leftJoin("users","epquotations.userid","=","users.id")
            ->where('epquotations.client_id', $clientid)
            ->whereIn('epquotations.userid', $users)
            ->where('epquotations.booking_from','<>','shaadicart')
            ->when($allowsearch, function ($q) use ($search) {
                $q->where(function($x) use ($search){
                    $x->where('epquotations.name','like',"%$search%")
                      ->orWhere('quotations.accepted_amount','like',"%$search%");
                });
            })
            ->orderBy('epquotations.id','desc');
        
            if (!empty($item_id)) {
                $data = $query->where('epquotations.id', $item_id)->first();
            } else {
                $data = $query->paginate(10);
            }
        
            /* ================= TRANSFORM ================= */
        
            $transformFn = function ($q) {

                /* ================= QUOTATION TITLE ================= */

                $normalizedTitle = !empty($q->quotation_title)
                    ? $q->quotation_title
                    : $q->name;

                $q->quotation_title = $normalizedTitle;
                $q->quotation_title_display_text = uiFast($normalizedTitle);

                /* ================= NORMAL TRANSLATION ================= */
                // PDF
                $q->pdf = !empty($q->pdf)
                    ? "https://planawedding.in/storage/".$q->pdf
                    : null;
        
                // Fields to translate (EXCLUDING booking_from)
                foreach ([
                    'event_type',
                    'event_location',
                    'name',
                    'genname',
                    'source'
                ] as $field) {
                    if (!empty($q->$field)) {
                        $q->{$field.'_value'} = $q->$field;
                        $q->{$field.'_display_text'} = uiFast($q->$field);
                        unset($q->$field);
                    }
                }
        
                return $q;
            };
        
            if ($data instanceof \Illuminate\Pagination\LengthAwarePaginator) {
                $data->getCollection()->transform($transformFn);
            } elseif ($data) {
                $data = $transformFn($data);
            }
        
            return response()->json([
                'message' => uiFast('Quotations list'),
                'status'  => '1',
                'data'    => $data,
                'base_path' => 'https://planawedding.in/storage/',
                'user_role' => $user_role,
                'logged_in_user' => $user_details,
            ], 200);
        }
        
        
