            ->leftJoin("users","epquotations.userid","=","users.id")
            ->where('epquotations.client_id', $clientid)
            ->whereIn('epquotations.userid', $users)
            ->where('epquotations.booking_from','<>','shaadicart')
            ->when($allowsearch, function ($q) use ($search) {
                $q->where(function($x) use ($search){
                    $x->where('epquotations.name','like',"%$search%")
                      ->orWhere('quotations.accepted_amount','like',"%$search%");
                });
            })
            ->orderBy('epquotations.id','desc');
        
            if (!empty($item_id)) {
                $data = $query->where('epquotations.id', $item_id)->first();
            } else {
                $data = $query->paginate(10);
            }
        
            /* ================= TRANSFORM ================= */
        
            $transformFn = function ($q) {

                /* ================= PDF ================= */

                $q->pdf = !empty($q->pdf)
                    ? "https://planawedding.in/storage/".$q->pdf
                    : null;

                /* ================= NORMAL TRANSLATION ================= */

                foreach ([
                    'event_type',
                    'event_location',
                    'name',
                    'genname',
                    'source'
                ] as $field) {

                    if (isset($q->$field)) {

                        $value = $q->$field;

                        // ✅ CLEAN FAKE NULLS
                        if ($value === null || $value === "null" || $value === "NULL" || $value === "undefined" || $value === "") {
                            $value = null;
                        }

                        $q->{$field.'_value'} = $value;
                        $q->{$field.'_display_text'} = !empty($value) ? uiFast($value) : null;

                        unset($q->$field);
                    }
                }

                /* ===================================================== */
                /* ✅ QUOTATION TITLE PRIORITY (NULL SAFE) */
                /* ===================================================== */

                $titleCandidates = [
                    $q->quotation_title_value ?? null,
                    $q->name_value ?? null,
                    $q->genname_value ?? null
                ];

                $quotationTitle = null;

                foreach ($titleCandidates as $candidate) {

                    if (
                        $candidate !== null &&
                        $candidate !== "null" &&
                        $candidate !== "NULL" &&
                        $candidate !== "undefined" &&
                        trim($candidate) !== ""
                    ) {
                        $quotationTitle = $candidate;
                        break;
                    }
                }

                $q->quotation_title = $quotationTitle;

                $q->quotation_title_display_text = !empty($quotationTitle)
                    ? uiFast($quotationTitle)
                    : null;

                return $q;
            };

        
            if ($data instanceof \Illuminate\Pagination\LengthAwarePaginator) {
                $data->getCollection()->transform($transformFn);
            } elseif ($data) {
                $data = $transformFn($data);
            }
        
            return response()->json([
                'message' => uiFast('Quotations list'),
                'status'  => '1',
                'data'    => $data,
                'base_path' => 'https://planawedding.in/storage/',
                'user_role' => $user_role,
                'logged_in_user' => $user_details,
            ], 200);
        }
        
