                'email' => $user->email,
                'mobile' => $user->mobile,
                'business_name' => $user->business_name
            ];
        
            $useraccess = $this->checkeditaccess($token);
            $user_role  = $useraccess['role'];
        
            $item_id = $request->id;
            $search  = $request->search;
            $allowsearch = !empty($search);
        
            /* ================= USER SCOPE ================= */
            $users = [];
        
            if ($user_role == 'admin' || $user_role == 'partner admin') {
                $users = User::where('team_id', $user->id)->pluck('id')->toArray();
                $users[] = $user->id;
            } elseif ($user_role == 'sub admin') {
                $users = User::where('team_id', $user->team_id)->pluck('id')->toArray();
                $users[] = $user->team_id;
            } elseif ($user_role == 'team member') {
                $users[] = $user->id;
            } else {
                return response()->json([
                    'message' => uiFast('User do not have access'),
                    'status'  => '0',
                    'data'    => [],
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                ], 401);
            }
        
            /* ================= BASE QUERY ================= */
            $baseQuery = Epquotation::select([
                'epquotations.id',
                'epquotations.quotationid',
                'epquotations.name',
                'epquotations.quotation_title', // ✅ ADDED
                'epquotations.email',
                'epquotations.mobile',
        
                DB::raw('(CASE 
                    WHEN epquotations.booking_from = "eventplanner" THEN "Self"
                    ELSE "Plan a Wedding"
                END) AS source'),
        
                'epquotations.event_date',
                'users.name as genname',
                'epquotations.event_location',
                'epquotations.client_id',
                'epquotations.event_type',
                'epquotations.inserted_at',
                'epquotations.update_time',   // ✅ ADD THIS
                'epquotations.received_status',
                'epquotations.userid',
                'epquotations.quotation_number',
                'epquotations.order_confirm',
                'epquotations.booking_from',
                'payorders.quotedate',
                'quotations.accepted_amount',
                'epquotations.pdf',
                'temp_quotations.pdf_file as temp_pdf',
        
                DB::raw("TIMESTAMPDIFF(HOUR,epquotations.inserted_at,now()) as hours"),
            ])
            ->leftJoin("payorders","epquotations.quotationid","=","payorders.quoteid")
            ->leftJoin("quotations","epquotations.quotationid","=","quotations.id")
            ->leftJoin("users","epquotations.userid","=","users.id")
            ->leftJoin("temp_quotations","temp_quotations.quotation_id","=","epquotations.quotationid")
            ->whereIn('epquotations.userid', $users)
            ->where('epquotations.booking_from','<>','shaadicart')
            ->orderBy('epquotations.id','desc');
        
            if ($allowsearch) {
                $baseQuery->where(function($q) use ($search){
                    $q->where('epquotations.name','like',"%$search%")
                      ->orWhere('epquotations.quotation_title','like',"%$search%")
                      ->orWhere('quotations.accepted_amount','like',"%$search%");
                });
            }
        
            /* ================= SINGLE / LIST ================= */
            if (!empty($item_id)) {
        
                $data = $baseQuery->where('epquotations.id',$item_id)->first();
        
                if ($data) {
        
                    /*
                        $data->pdf = $data->temp_pdf ?? $data->pdf;
                        unset($data->temp_pdf);
                    */
                    $data->pdf = null;
        
                    // ✅ NORMALIZE TITLE
                    $normalizedTitle = !empty($data->quotation_title)
                        ? $data->quotation_title
                        : $data->name;
                    
                    /*$data->quotation_title_value = $normalizedTitle;*/
                    $data->quotation_title_display_text = uiFast($normalizedTitle);

        
                    $data = $this->translateQuoteRow($data);
                }
        
            } else {
        
                $data = $baseQuery->paginate(10);
        
                $data->getCollection()->transform(function ($row) {
        
                    /*
                    
                        $row->pdf = $row->temp_pdf ?? $row->pdf;
                        unset($row->temp_pdf);
                    */
                    $pdfVisible = false;

                    if (!empty($row->update_time) && !empty($row->pdf)) {

                        $updateTime = \Carbon\Carbon::parse($row->update_time, 'UTC')
                            ->setTimezone('Asia/Kolkata');

                        // ✅ 18 Feb 2026 12:30 PM IST
                        $cutoffTime = \Carbon\Carbon::create(2026, 2, 18, 12, 30, 0, 'Asia/Kolkata');

                        if ($updateTime->greaterThanOrEqualTo($cutoffTime)) {
                            $pdfVisible = true;
                        }
                    }

                    $row->pdf = $pdfVisible
                        ? 'https://planawedding.in/storage/'.$row->pdf
                        : null;
                    
                    // ✅ NORMALIZE TITLE
                    $normalizedTitle = !empty($row->quotation_title)
                        ? $row->quotation_title
                        : $row->name;
                    
                    /*$row->quotation_title_value = $normalizedTitle;*/
                    $row->quotation_title_display_text = uiFast($normalizedTitle);
        
                    return $this->translateQuoteRow($row);
                });
            }
        
            return response()->json([
                'message' => uiFast('Quotations list'),
                'status'  => '1',
                'data'    => $data,
                'user_role' => $user_role,
                'logged_in_user' => $user_details,
                'base_url' => 'https://planawedding.in/storage/',
            ], 200);
        }

        
        
        /* =====================================================
           🔤 TRANSLATE QUOTE ROW (FAST & SAFE)
           booking_from intentionally NOT translated
        ===================================================== */
    private function translateQuoteRow($q)
        {
            foreach ([
                'name',
                'event_type',
                'event_location',
                'genname',
                'source'
            ] as $field) {
                if (!empty($q->$field)) {
                    $q->{$field.'_value'} = $q->$field;
                    $q->{$field.'_display_text'} = uiFast($q->$field);
                    unset($q->$field);
                }
            }
            return $q;
        } 
