    public function weddingguidegeteditquote_1(Request $request)
        {
            $token = $request->header('Authorization');
            $user  = $this->getuser($token);
        
            if (!$user) {
                return response()->json([
                    'message' => uiFast('User not found'),
                    'status' => '0',
                    'data' => [],
                    'tempquote' => [],
                    'user_role' => "",
                    'logged_in_user' => [],
                    'base_url' => 'https://planawedding.in/storage/',
                ], 401);
            }
        
            $user_details = [
                'name' => $user->name,
                'email' => $user->email,
                'mobile' => $user->mobile,
                'business_name' => $user->business_name
            ];
        
            $useraccess = $this->checkeditaccess($token);
            $user_role  = $useraccess['role'];
        
            $rules = [
                'quotation_id' => 'required|numeric',
                'epquote_id'   => 'required|numeric',
                'client_id'    => 'required|numeric',
                'quoyetype'    => 'required',
            ];
        
            $validator = Validator::make($request->all(), $rules);
        
            if ($validator->fails()) {
                return response()->json([
                    'message' => $validator->messages(),
                ], 422);
            }
        
            /* ================= USER SCOPE ================= */
            if ($user_role == 'admin' || $user_role == 'partner admin') {
                $users = User::where('team_id',$user->id)->pluck('id')->toArray();
                $users[] = $user->id;
            } elseif ($user_role == 'sub admin') {
                $users = User::where('team_id',$user->team_id)->pluck('id')->toArray();
                $users[] = $user->id;
            } elseif ($user_role == 'team member') {
                $users = [$user->id];
            } else {
                return response()->json([
                    'message' => uiFast('User do not have access'),
                    'status' => '0',
                    'data' => [],
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                ], 401);
            }
        
            /* ================= CORE DATA ================= */
            $quotation_id = $request->quotation_id;
            $epquote_id   = $request->epquote_id;
            $user_id      = $user->id;
            $team_id      = $user->team_id;
        
            $epquotation = Epquotation::where('id',$epquote_id)
                ->whereIn('userid',$users)
                ->first();
        
            if (!$epquotation) {
                return response()->json([
                    'message' => uiFast('Quotation not found'),
                    'data' => [],
                    'tempquote' => [],
                    'status' => '0',
                    'exists' => '',
                    'same_user' => '',
                    'user_role' => "",
                    'logged_in_user' => [],
                    'base_url' => 'https://planawedding.in/storage/',
                ], 200);
            }
        
            /* ================= PDF ================= */
            $pdf_file = $this->genpdftemp(
                $epquotation->id,
                $user->id,
                $user->company_logo,
                $user->email,
                $user->mobile,
                $user->business_name
            );
        
            $epquotation->pdf = $pdf_file;
        
            /* ================= TRANSLATE MAIN FIELDS ================= */
            foreach (['name','event_type','event_location','description'] as $field) {
                if (!empty($epquotation->$field)) {
                    $epquotation->{$field.'_value'} = $epquotation->$field;
                    $epquotation->{$field.'_display_text'} = uiFast($epquotation->$field);
                    unset($epquotation->$field);
                }
            }
            
            /* ================= TRANSLATE item ================= */
            /* ================= TRANSLATE item (particular) ================= */
            if (!empty($epquotation->item)) {
            
                $items = json_decode($epquotation->item, true);
            
                if (is_array($items)) {
            
                    foreach ($items as &$i) {
            
                        if (!empty($i['particular'])) {
            
                            $original = $i['particular'];
            
                            $i['particular_value'] = $original;
            
                            // 🔥 Use Google translate (NOT transliteration) 
                            $i['particular_display_text'] = translateQuoteItemName(
                                $original,
                                app()->getLocale()
                            );
            
                            unset($i['particular']);
                        }
                    }
                }
            
                $epquotation->item = $items;
            }


        
            /* ================= TRANSLATE added_item ================= */
            if (!empty($epquotation->added_item)) {
                $items = json_decode($epquotation->added_item, true);
        
                if (is_array($items)) {
                    foreach ($items as &$i) {
                        if (!empty($i['parti'])) {
                            $i['parti_value'] = $i['parti'];
                            $i['parti_display_text'] =
                                translateQuoteItemName($i['parti']);
                            unset($i['parti']);
                        }
                    }
                }
                $epquotation->added_item = $items;
            }
        
            /* ================= TEMP QUOTE ================= */
            $tempquote = TempQuotation::where('quotation_type','existing')
                ->where('quotation_id',$quotation_id)
                ->whereIn('event_planner_id',$users)
                ->first();
        
            if ($tempquote) {
                $tempquote->pdf_file = $pdf_file;
                $tempquote->save();
                $exists = 'yes';
            } else {
                $tempquote = new TempQuotation();
                $tempquote->event_planner_id = $epquotation->userid;
                $tempquote->items = $epquotation->item;
                $tempquote->items_added = $epquotation->added_item;
                $tempquote->quotation_id = $epquotation->quotationid;
                $tempquote->quotation_type = 'existing';
                $tempquote->booking_from = $epquotation->booking_from; // ❌ NOT TRANSLATED
                $tempquote->pdf_file = $pdf_file;
                $tempquote->save();
                $exists = 'no';
            }
        
            return response()->json([
                'message' => uiFast('Quotation details'),
                'data' => $epquotation,
                'tempquote' => $tempquote,
                'status' => '1',
                'exists' => $exists,
                'same_user' => ($epquotation->userid == $user->id) ? 'yes' : 'no',
                'user_role' => $user_role,
                'logged_in_user' => $user_details,
                'base_url' => 'https://planawedding.in/storage/',
            ], 200);
        } 
