            );

            $epquotation->pdf = $pdf_file;

            /* ================= TRANSLATE MAIN FIELDS (CRASH SAFE) ================= */

            foreach (['name','event_type','event_location','description'] as $field)
            {
                if (isset($epquotation->$field))
                {
                    $value = $epquotation->$field;

                   
                    // ✅ CRITICAL FIX → Normalize datatype
                    if (is_array($value)) {
                        $value = implode(', ', $value);
                    }

                    if (is_object($value)) {
                        $value = json_encode($value);
                    }

                    if (
                        $value !== null &&
                        $value !== "null" &&
                        $value !== "undefined" &&
                        trim((string)$value) !== ""
                    )
                    {
                        $epquotation->{$field.'_value'} = $value;
                        $epquotation->{$field.'_display_text'} = uiFast($value);
                    }

                    unset($epquotation->$field);
