            if (!empty($epquotation->added_item)) {

                $items = json_decode($epquotation->added_item, true);

                if (is_array($items)) {

                    foreach ($items as &$i) {

                        if (!empty($i['parti'])) {

                            $i['parti_value'] = $i['parti'];

                            $i['parti_display_text'] = translateQuoteItemName($i['parti']);

                            unset($i['parti']);
