                    }
                }

                $epquotation->added_item = $items;
            }

            /* ================= TEMP QUOTE ================= */

            $tempquote = TempQuotation::where('quotation_type','existing')
                ->where('quotation_id',$quotation_id)
                ->whereIn('event_planner_id',$users)
                ->first();

            if ($tempquote) {

                $tempquote->pdf_file = $pdf_file;
                $tempquote->save();
                $exists = 'yes';

            } else {

                $tempquote = new TempQuotation();
                $tempquote->event_planner_id = $epquotation->userid;

                // ✅ Encode arrays back to JSON (SAFE)
                $tempquote->items = json_encode(
                    $epquotation->item,
                    JSON_UNESCAPED_UNICODE
                );

                $tempquote->items_added = json_encode(
                        $epquotation->added_item,
                        JSON_UNESCAPED_UNICODE
                    );

                $tempquote->quotation_id = $epquotation->quotationid;
                $tempquote->quotation_type = 'existing';
                $tempquote->booking_from = $epquotation->booking_from;
                $tempquote->pdf_file = $pdf_file;
                $tempquote->save();

                $exists = 'no';
            }

            return response()->json([
