                'tempquote' => $tempquote,
                'status' => '1',
                'exists' => $exists,
                'same_user' => ($epquotation->userid == $user->id) ? 'yes' : 'no',
                'user_role' => $user_role,
                'logged_in_user' => $user_details,
                'base_url' => 'https://planawedding.in/storage/',
            ], 200);
        }

    private function translateEditQuoteData_1($epquotation)
        {
            if (!$epquotation) {
                return $epquotation;
            }
        
            $lang = app()->getLocale();
        
            $translate = function ($text) use ($lang) {
                if (!$text) return $text;
                if ($lang === 'en') return $text;
        
                // 🔥 Real translation (cached)
                return translateText($text, $lang);
            };
        
            /* -------- item (particular) -------- */
            if (!empty($epquotation->item)) {
        
                $items = is_array($epquotation->item)
                    ? $epquotation->item
                    : json_decode($epquotation->item, true);
        
                if (is_array($items)) {
        
                    foreach ($items as &$row) {
        
                        if (!empty($row['particular'])) {
        
                            $original = $row['particular'];
        
                            $row['particular_value'] = $original;
                            $row['particular_display_text'] = translateQuoteItemName($original);
        
                            unset($row['particular']);
                        }
                    }
        
                    $epquotation->item = $items;
                }
            }
        
            /* -------- added_item (parti) -------- */
            if (!empty($epquotation->added_item)) {
        
                $itemsAdded = is_array($epquotation->added_item)
                    ? $epquotation->added_item
                    : json_decode($epquotation->added_item, true);
        
                if (is_array($itemsAdded)) {
        
                    foreach ($itemsAdded as &$row) {
        
                        if (!empty($row['parti'])) {
        
                            $original = $row['parti'];
        
                            $row['parti_value'] = $original;
                            $row['parti_display_text'] = translateQuoteItemName($original);
        
                            unset($row['parti']);
                        }
                    }
        
                    $epquotation->added_item = $itemsAdded;
                }
            }
        
            /* -------- simple fields -------- */
            
            
            if (!empty($epquotation->name)) {
                $epquotation->name_value = $epquotation->name;
                $epquotation->name_display_text = $translate($epquotation->name);
                unset($epquotation->name);
            }
        
            if (!empty($epquotation->event_location)) {
                $epquotation->event_location_value = $epquotation->event_location;
                $epquotation->event_location_display_text = $translate($epquotation->event_location);
                unset($epquotation->event_location);
            }
        
            if (!empty($epquotation->event_type)) {
                $epquotation->event_type_value = $epquotation->event_type;
                $epquotation->event_type_display_text = $translate($epquotation->event_type);
                unset($epquotation->event_type);
            }
            if (!empty($epquotation->description)) {
                $epquotation->description_value = $epquotation->description;
                $epquotation->description_display_text = $translate($epquotation->description);
                unset($epquotation->description);
            }
            return $epquotation;
