    public function weddingguideeditagentcart(Request $request)
        {
            $token = $request->header('Authorization');
            $user = $this->getuser($token);
            
            if($user) 
            {
                $mydateinsert = date('d/m/Y');

                $user_details = [
                    'name' => $user->name,
                    'email' => $user->email,
                    'mobile' => $user->mobile,
                    'business_name' => $user->business_name
                ];
                
                $useraccess = $this->checkeditaccess($token);
                $user_role = $useraccess['role'];
                
                $rules = [
                    'client_id'        => 'required|numeric',
                    'mobile'           => 'required',
                    'event_date'       => 'required|date_format:d/m/Y',
                    'event_type'       => 'required|in:wedding,birthday,corporate',
                    'event_location'   => 'required',
                    'transport_cost'   => 'required|numeric',
                    'total_price'      => 'required|numeric',
                    'quotation_id'     => 'required'
                ];
                
                $validator = Validator::make($request->all(), $rules);

                if ($validator->fails()) 
                {
                    return response()->json([
                        'message' => $validator->messages(),
                    ]);
                }

                /* ---------------- FETCH QUOTES ---------------- */

                $epquotation = Epquotation::where('quotationid',$request->quotation_id)
                                ->where('userid',$user->id)
                                ->first();
            
                if(!$epquotation)
                {
                    return response()->json([
                        'message' => uiFast('Event Planner Quotation not found'),
                        'status' => '0',
                        'data' => [],
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }

                $quotation = Quotation::where('id',$epquotation->quotationid)->first();
                    
                if(!$quotation)
                {
                    return response()->json([
                        'message' => uiFast('Quotation not found'),
                        'status' => '0',
                        'data' => [],
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }

                /****************** START EDIT LOGIC ******************/

                $name            = urldecode($request->name);
                $email           = urldecode($request->email);
                $mobile          = $request->mobile;
                $event_date      = $request->event_date;
                $event_type      = ucfirst($request->event_type);
                $event_location  = $request->event_location;
                $transport_cost  = $request->transport_cost;
                $description     = urldecode($request->description);
                $manual_discount = $request->manual_discount ?? 0;

                $listitems  = $request->listitems ?? "";
                $listitems2 = $request->listitems2 ?? "";

                $today = date("d-m-y-his");

                /* ---------------- ITEMS BUILD ---------------- */

                $pricetoinsert = 0;

                /* MAIN ITEMS */
                $items = [];
                if(!empty($listitems))
                {
                    $listitems = substr($listitems, 0, -1);
                    $listitems = explode("#",$listitems);

                    $j = 0;
                    foreach($listitems as $i => $oneitem)
                    {

                        if(empty(trim($oneitem))) {
                            continue;
                        }
                        $oneitem = explode("^",$oneitem);

                        $items[$i+1]['particular']   = $oneitem[0];
                        $items[$i+1]['item_qty']     = $oneitem[1];
                        $items[$i+1]['item_height']  = $oneitem[2];
                        $items[$i+1]['item_width']   = $oneitem[3];
                        $items[$i+1]['item_price']   = $oneitem[4];
                        $items[$i+1]['net_price']    = $oneitem[5];
                        $items[$i+1]['pack_desc']    = $oneitem[6];
                        $items[$i+1]['partidays']    = $oneitem[7];
                        $items[$i+1]['itemimage']    = ($oneitem[8] == 'undefined') ? "" : $oneitem[8];
                        $items[$i+1]['size']         = "";

                        $pricetoinsert += $oneitem[5];
                    }
                }

                $item_json = json_encode($items);

                /* ADDED ITEMS */
                $itemsadded = [];
                if(!empty($listitems2))
                {
                    $listitems2 = substr($listitems2, 0, -1);
                    $listitems2 = explode("#",$listitems2);

                    foreach($listitems2 as $i => $oneitems)
                    {
                        if(empty(trim($oneitems))) {
                            continue;
                        }
                        $oneitems = explode("^",$oneitems);

                        $itemsadded[$i+1]['parti']      = $oneitems[0];
                        $itemsadded[$i+1]['qtt']        = $oneitems[1];
                        $itemsadded[$i+1]['heightee']   = $oneitems[2];
                        $itemsadded[$i+1]['widthee']    = $oneitems[3];
                        $itemsadded[$i+1]['ammt']       = $oneitems[4];
                        $itemsadded[$i+1]['calc']       = $oneitems[5];
                        $itemsadded[$i+1]['partidays']  = $oneitems[6];
                        $itemsadded[$i+1]['itemimage']  = ($oneitems[7] == 'undefined') ? "" : $oneitems[7];
                        $itemsadded[$i+1]['size']       = "";

                        $pricetoinsert += $oneitems[5];
                    }
                }

                $itemsadded_json = json_encode($itemsadded);

                $total_data_amount = $pricetoinsert;

                /* ---------------- UPDATE QUOTATION ---------------- */

                $quotation->item            = $item_json;
                $quotation->name            = $name;
                $quotation->email           = $email;
                $quotation->mobile          = $mobile;
                $quotation->event_date      = $event_date;
                $quotation->total_price     = $total_data_amount;
                $quotation->added_item      = $itemsadded_json;
                $quotation->manual_discount = $manual_discount;
                $quotation->event_location  = strtolower($event_location);
                $quotation->generated_by    = $user->id;
                $quotation->quotation_sent  = 1;

                $quotation->save();

                /* ---------------- UPDATE EPQUOTATION ---------------- */

                $epquotation->item            = $item_json;
                $epquotation->name            = $quotation->name;
                $epquotation->email           = $quotation->email;
                $epquotation->mobile          = $quotation->mobile;
                $epquotation->event_date      = $event_date;
                $epquotation->total_price     = $total_data_amount;
                $epquotation->added_item      = $itemsadded_json;
                $epquotation->manual_discount = $manual_discount;
                $epquotation->event_location  = strtolower($event_location);

                $epquotation->save();

                /* ---------------- PDF REGENERATION FIX 🔥 ---------------- */

                $pdfPath = $this->sendagenteditedquote_new(
                    $quotation->id,
                    $user->id,
                    $user->company_logo
                );

                if(!empty($pdfPath))
                {
                    $quotation->pdf   = $pdfPath;
                    $quotation->save();

                    $epquotation->pdf = $pdfPath;
                    $epquotation->save();
                }

                /* ---------------- TRANSLATION ---------------- */

                $epquotation = $this->translateEditQuoteData($epquotation);

                return response()->json([
                    'message' => uiFast('Quotation updated successfully and mailed to customer'),
                    'status' => '1',
                    'data' => $epquotation,
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                ], 200);
            } 
            else 
            {
                return response()->json([
                    'message' => uiFast('User not found'),
                    'status' => '0',
                    'data' => [],
                    'user_role' => "",
                    'logged_in_user' => [],
                ], 401);
            }
        }

    private function sendagenteditedquote_new($quotationid, $userid, $company_logo)
        {
            $today = date("d-m-y-his");

            $data = Quotation::where('id', $quotationid)
                ->where('generated_by', $userid)
                ->with('quser')
                ->first();

            if (!$data) {
                return null;
            }

            /* ---------- QUOTATION TITLE LOGIC ---------- */

            $epData = Epquotation::where('quotationid', $quotationid)
                ->where('userid', $userid)
                ->latest()
                ->first();

            $quotationTitle = '';

            if (!empty($epData->quotation_title)) {
                $quotationTitle = $epData->quotation_title;
            }

            $headingText = 'Wedding Quotation';

            if (!empty($quotationTitle)) {
                $headingText .= ' for ' . $quotationTitle;
            } elseif (!empty($data->name)) {
                $headingText .= ' for ' . $data->name;
            }

            /* ---------- INR FORMATTER ---------- */

            function formatInr($amount)
            {
                $amount = round($amount);
                $num = (string)$amount;

                if (strlen($num) <= 3) return $num;

                $last3 = substr($num, -3);
                $rest = substr($num, 0, -3);

                $rest = preg_replace("/\B(?=(\d{2})+(?!\d))/", ",", $rest);

                return $rest . "," . $last3;
            }

            /* ---------- LOGO FIX (BASE64 SAFE) ---------- */

            $logoHtml = '';

            if (!empty($company_logo)) {
                $logoPath = storage_path('app/public/' . $company_logo);

                if (file_exists($logoPath)) {
                    $type = pathinfo($logoPath, PATHINFO_EXTENSION);
                    $imageData = base64_encode(file_get_contents($logoPath));

                    $logoHtml = '<img src="data:image/' . $type . ';base64,' . $imageData . '" 
                                style="max-width:110px; max-height:70px;">';
                }
            }

            if (empty($logoHtml)) {
                $logoHtml = '<h2 style="margin:0; color:#863ac1;">' . $data->quser->business_name . '</h2>';
            }

            /* ---------- ITEMS ---------- */

            $cus_requirements = json_decode($data->item, true);
            $cus_added_item   = json_decode($data->added_item, true);

            $totalamount = 0;
            $itemselected = '';

            if ($cus_requirements != NULL) {
                foreach ($cus_requirements as $items) {

                    $particular = $items['particular'];
                    $qty        = $items['item_qty'];
                    $height     = $items['item_height'];
                    $width      = $items['item_width'];
                    $days       = $items['partidays'];
                    $net_price  = round($items['net_price']);
                    $desc       = $items['pack_desc'];
                    $itemimage  = $items['itemimage'];

                    $totalamount += $net_price;

                    if (!empty($qty)) {
                        $qtyDisplay = $qty;
                    } elseif (!empty($width) && !empty($height)) {
                        $qtyDisplay = $width . ' × ' . $height;
                    } else {
                        $qtyDisplay = '-';
                    }

                    $imageBlock = '';
                    if (!empty($itemimage)) {
                        $imageBlock = '<img src="' . $itemimage . '" style="width:45px;">';
                    }

                    $itemselected .= '
                        <tr>
                            <td style="padding:8px;">
                                ' . $particular . '<br>
                                <span style="font-size:10px;color:#777;">' . $desc . '</span>
                            </td>
                            <td style="padding:8px;text-align:center;">' . $days . '</td>
                            <td style="padding:8px;text-align:center;">' . $qtyDisplay . '</td>
                            <td style="padding:8px;text-align:center;">' . $imageBlock . '</td>
                            <td style="padding:8px;">₹ ' . formatInr($net_price) . ' /-</td>
                        </tr>';
                }
            }

            if ($cus_added_item != NULL) {
                foreach ($cus_added_item as $itemsadds) {

                    $particular = nl2br($itemsadds['parti']);
                    $qty        = $itemsadds['qtt'];
                    $height     = $itemsadds['heightee'];
                    $width      = $itemsadds['widthee'];
                    $days       = $itemsadds['partidays'];
                    $net_price  = round($itemsadds['calc']);
                    $itemimage  = $itemsadds['itemimage'];

                    $totalamount += $net_price;

                    if (!empty($qty)) {
                        $qtyDisplay = $qty;
                    } elseif (!empty($width) && !empty($height)) {
                        $qtyDisplay = $width . ' × ' . $height;
                    } else {
                        $qtyDisplay = '-';
                    }

                    $imageBlock = '';
                    if (!empty($itemimage)) {
                        $imageBlock = '<img src="' . $itemimage . '" style="width:45px;">';
                    }

                    $itemselected .= '
                        <tr>
                            <td style="padding:8px;">' . $particular . '</td>
                            <td style="padding:8px;text-align:center;">' . $days . '</td>
                            <td style="padding:8px;text-align:center;">' . $qtyDisplay . '</td>
                            <td style="padding:8px;text-align:center;">' . $imageBlock . '</td>
                            <td style="padding:8px;">₹ ' . formatInr($net_price) . ' /-</td>
                        </tr>';
                }
            }

            /* ---------- TOTAL ---------- */

            $amountpayable = $totalamount;

            /* ---------- PDF HTML ---------- */

            $mailbody = '

            <div style="width:100%; font-family: DejaVu Sans, sans-serif; font-size:12px;">

                <table style="width:100%; border:1px solid #863ac1;">
                    <tr>
                        <td style="text-align:center; padding:15px;">
                            ' . $logoHtml . '
                            <p style="font-size:11px;">
                                ' . $data->quser->email . ' | ' . $data->quser->mobile . '
                            </p>
                        </td>
                    </tr>
                </table>

                <table style="width:100%; margin-top:8px;">
                    <tr>
                        <td style="background:#863ac1; color:white; text-align:center; padding:8px; font-size:15px;">
                            ' . $headingText . '
                        </td>
                    </tr>
                </table>

                <table style="width:100%; margin-top:8px; border:1px solid #863ac1;">
                    <tr style="background:#f4ecfb;">
                        <td style="padding:8px;"><strong>Enquiry Date</strong></td>
                        <td style="padding:8px;"><strong>Event Date</strong></td>
                        <td style="padding:8px;"><strong>Location</strong></td>
                    </tr>
                    <tr>
                        <td style="padding:8px;">' . date('d/m/Y', strtotime($data->created_at)) . '</td>
                        <td style="padding:8px;">' . $data->event_date . '</td>
                        <td style="padding:8px;">' . $data->event_location . '</td>
                    </tr>
                </table>

                <table style="width:100%; margin-top:10px; border:1px solid #863ac1;">
                    <tr style="background:#863ac1; color:white;">
                        <th style="padding:8px;">Particular</th>
                        <th style="padding:8px;">Days</th>
                        <th style="padding:8px;">Qty / Size</th>
                        <th style="padding:8px;">Image</th>
                        <th style="padding:8px;">Amount</th>
                    </tr>

                    ' . $itemselected . '

                </table>

                <table style="width:100%; margin-top:10px; border:1px solid #863ac1;">
                    <tr style="background:#f4ecfb;">
                        <td colspan="4" style="padding:10px; text-align:right; font-size:14px;">
                            <strong>Total Amount</strong>
                        </td>
                        <td style="padding:10px; font-size:14px;">
                            <strong>₹ ' . formatInr($amountpayable) . ' /-</strong>
                        </td>
                    </tr>
                </table>

                <div style="margin-top:20px; font-size:10px; text-align:center; color:#777;">
                    Powered By ' . $data->quser->business_name . '
                </div>

            </div>';

            /* ---------- PDF GENERATION ---------- */

            $pdf = PDF::loadView('pdfs.invoices', ['mailbody' => $mailbody])
                ->setPaper('A4', 'portrait');

            $pdf->setOptions([
                'isPhpEnabled' => true,
                'isRemoteEnabled' => true
            ]);

            $filename = 'admin_uploads/pdf/' . $today . '-quotation.pdf';

            Storage::put($filename, $pdf->output());

            return $filename;
        } 

    public function editagentcart_1(Request $request)
        {
            $token = $request->header('Authorization');
            $user = $this->getuser($token);
            
            if($user) 
            {
                $mydateinsert = date('d/m/Y');

