    private function sendquotationagent($quotationid,$userid)
        {
            $today = date("d-m-y-his");

            $data = Quotation::where('id',$quotationid)
                    ->where('generated_by',$userid)
                    ->with('quser')
                    ->first();

            if(!$data) {
                return false;
            }

            $epData = Epquotation::where('quotationid', $quotationid)
            ->where('userid', $userid)
            ->latest()
            ->first();

            $quotationTitle = '';

            if(!empty($epData->quotation_title)) {
                $quotationTitle = $epData->quotation_title;
            }

            /* ---------- QUOTATION HEADING LOGIC ---------- */

            $headingText = 'Wedding Quotation';

            if(!empty($quotationTitle))
            {
                $headingText .= ' for '.$quotationTitle;
            }
            else if(!empty($data->name))
            {
                $headingText .= ' for '.$data->name;
            }

            /* ---------- INR FORMATTER (Indian Separators) ---------- */
            function formatInr($amount)
            {
                $amount = round($amount);
                $num = (string)$amount;

                if(strlen($num) <= 3) return $num;

                $last3 = substr($num, -3);
                $rest = substr($num, 0, -3);

                $rest = preg_replace("/\B(?=(\d{2})+(?!\d))/", ",", $rest);

                return $rest . "," . $last3;
            }

            /* ---------- LOGO FIX ---------- */

           

            /* ---------- DOMPDF PERFECT LOGO FIX ---------- */

            $logoHtml = '';

            $logoFile = $data->quser->company_logo;

            if(!empty($logoFile))
            {
                $logoPath = storage_path('app/public/'.$logoFile);

                if(file_exists($logoPath))
                {
                    $type = pathinfo($logoPath, PATHINFO_EXTENSION);
                    $imageData = base64_encode(file_get_contents($logoPath));

                    $logoHtml = '<img src="data:image/'.$type.';base64,'.$imageData.'" style="max-width:110px; max-height:70px;">';
                }
            }

            if(empty($logoHtml))
            {
                $logoHtml = '<h2 style="margin:0; color:#863ac1;">'.$data->quser->business_name.'</h2>';
            }

            $cus_requirements = json_decode($data->item, true);
            $cus_added_item   = json_decode($data->added_item, true);

            $cus_transport_cost   = round($data->transport_cost);
            $cus_manual_discount  = round($data->manual_discount);

            $totalamount = 0;
            $itemselected = '';

            /* ---------- MAIN ITEMS ---------- */
            if($cus_requirements != NULL)
            {
                foreach($cus_requirements as $items)
                {
                    $particular   = $items['particular'];
                    $qty          = $items['item_qty'];
                    $height       = $items['item_height'];
                    $width        = $items['item_width'];
                    $days         = $items['partidays'];
                    $net_price    = round($items['net_price']);
                    $desc         = $items['pack_desc'];
                    $itemimage    = $items['itemimage'];

                    $totalamount += $net_price;

                    /* Qty OR Width × Height */
                    if(!empty($qty)) {
                        $qtyDisplay = $qty;
                    } 
                    else if(!empty($width) && !empty($height)) {
                        $qtyDisplay = $width.' × '.$height;
                    } 
                    else {
                        $qtyDisplay = '-';
                    }

                    /* Image */
                    $imageBlock = '';
                    if(!empty($itemimage)) {
                        $imageBlock = '<img src="'.$itemimage.'" style="width:45px; height:auto;">';
                    }

                    $itemselected .= '
                        <tr>
                            <td style="padding:8px;">
                                '.$particular.'<br>
                                <span style="font-size:10px;color:#777;">'.$desc.'</span>
                            </td>
                            <td style="padding:8px;text-align:center;">'.$days.'</td>
                            <td style="padding:8px;text-align:center;">'.$qtyDisplay.'</td>
                            <td style="padding:8px;text-align:center;">'.$imageBlock.'</td>
                            <td style="padding:8px;">₹ '.formatInr($net_price).' /-</td>
                        </tr>';
                }
            }

            /* ---------- ADDED ITEMS ---------- */
            if($cus_added_item != NULL)
            {
                foreach($cus_added_item as $itemsadds)
                {
                    $particular = nl2br($itemsadds['parti']);
                    $qty        = $itemsadds['qtt'];
                    $height     = $itemsadds['heightee'];
                    $width      = $itemsadds['widthee'];
                    $days       = $itemsadds['partidays'];
                    $net_price  = round($itemsadds['calc']);
                    $itemimage  = $itemsadds['itemimage'];

                    $totalamount += $net_price;

                    if(!empty($qty)) {
                        $qtyDisplay = $qty;
                    } 
                    else if(!empty($width) && !empty($height)) {
                        $qtyDisplay = $width.' × '.$height;
                    } 
                    else {
                        $qtyDisplay = '-';
                    }

                    $imageBlock = '';
                    if(!empty($itemimage)) {
                        $imageBlock = '<img src="'.$itemimage.'" style="width:45px;">';
                    }

