                    </tr>';

                $finalamount -= $cus_manual_discount;
            }

            $amountpaypable = $finalamount;

            /* ---------- BEAUTIFIED PDF HTML ---------- */

            $mailbody = '

            <div style="width:100%; font-family: DejaVu Sans, sans-serif; font-size:12px;">

