                                        foreach ($data as $column => $value)
                                        {
                                            $row->$column = $value; // dynamically assign values
                                        }
                                    */
    
                                    $itemadvancetotalbudget =  $request->totalbudget;
    
                                    $totaladvcance = $row->adv_amt_rcvd;
    
                                    $remainingtotal = $itemadvancetotalbudget - $totaladvcance;
    
    
    
                                    $row->totalbudget =  $itemadvancetotalbudget;
    
                                    $row->remainig_balance =  $remainingtotal;
    
                                    $row->save(); // save each row
                                }
    
                                return response()->json([
                                    'message' => uiFast('Payment details updated'),
                                    'status' => '1',
                                    'data' => $rows,
                                    'user_role' => $user_role,
                                    'logged_in_user' => $user_details,
                                    'base_url' => 'https://planawedding.in/storage/',
                                ], 201);
                            }
                        else if($itemget > 1)
                            {
                                    $rows = Budgetpay::where('client_id', $request->clientid)->orderBy('id', 'asc')->get();
                                    
                                     
                                    $clientId = $request->clientid;
    
                                    $payments = Budgetpay::where('client_id', $clientId)
                                                ->orderBy('id', 'asc') // or 'created_at'
                                                ->get();
    
                                   
                                    $previousRemaining = null;
    
                                    foreach ($payments as $payment) {
                                            if ($previousRemaining === null) {
                                                // First row
                                                $remaining = $request->totalbudget - $payment->adv_amt_rcvd;
                                            } else {
                                                // Subsequent rows
                                                $remaining = $previousRemaining - $payment->adv_amt_rcvd;
                                            }
                                            

                                            // Prevent negative balances
                                            //$payment->remainig_balance = max(0, $remaining);
                                            $payment->totalbudget = $request->totalbudget;
                                            $payment->remainig_balance = $remaining;
                                            $payment->save();
    
                                            // Update tracker for next row
                                            $previousRemaining = $payment->remainig_balance;
                                        }    
    
                                    return response()->json([
                                        'message' => uiFast('Payment details updated'),
                                        'status' => '1',
                                        'data' => $rows,
                                        'user_role' => $user_role,
                                        'logged_in_user' => $user_details,
                                        'base_url' => 'https://planawedding.in/storage/',
                                    ], 201);
                            }
                        else 
                            {
                                    return response()->json([
                                    'message' => uiFast('No advance amount exits'),
                                    'status' => '0',
                                    'data' => [],
                                    'user_role' => $user_role,
                                    'logged_in_user' => $user_details,
                                    'base_url' => 'https://planawedding.in/storage/',
                                ], 503);
                            }
                    }
                }
            else
                {
                    return response()->json([
                        'message' => uiFast('User not found'),
                        'status' => '0',
                        'data' => [],
                        'user_role' => "",
                        'logged_in_user' => [],
                    ], 401);
                }
    
        }
    public function weddingguidedeletesinglepayment(Request $request)
        {
            $token = $request->header('Authorization');
            $user = $this->getuser($token);
            
            if($user) 
            {
                $user_details = ['name' => $user->name,'email' => $user->email,'mobile' => $user->mobile,'business_name' => $user->business_name];
                
                $useraccess = $this->checkeditaccess($token);
                $user_role = $useraccess['role'];
                $user_access_array = $useraccess['access_array'];
                
                 
                $item_id = $request->id;
                
                if(empty($item_id))
                {
                    return response()->json([
                        'message' => uiFast('Payment id is mandatory'),
                        'status' => '0',
                        'data' => [],
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 400);
                }
                
                 
                $budgetpay = Budgetpay::where('id',$item_id)->first();
    
                if($budgetpay)
                {
                    $allow_delete = true;
     
                    if($allow_delete)
                    {
