    public function weddingguideaddpayments(Request $request)
        {
            $token = $request->header('Authorization');
            $user = $this->getuser($token);
            
            if($user) 
            {
                $user_details = ['name' => $user->name,'email' => $user->email,'mobile' => $user->mobile,'business_name' => $user->business_name];
                
                $useraccess = $this->checkeditaccess($token);
                
                $user_role = $useraccess['role'];
                $user_access_array = $useraccess['access_array'];
     
                 
                $rules = [
                            
                            'clientid' => 'required|numeric', 
                            'advanceamount' => 'required|numeric',
                            'advancedate' => 'required', 
                        ];
                        
                $error = Validator::make($request->all(), $rules);
    
                if($error->fails())
                {
                    $errors = $error->errors()->toArray();

                    // 🌐 Translate each validation message
                    foreach ($errors as $field => &$messages) {
                        foreach ($messages as &$msg) {
                            $msg = t($msg);
                        }
                    }

                    return response()->json([
                        'message' => $errors,
                    ], 422);
                }
                else
                {
                    $itemget = Budgetpay::where('client_id', $request->clientid)->latest()->first();
                    
                    
                    
    
                    if(!empty($itemget))
                        {
                            $itemgetbalancec = $itemget->remainig_balance;
                        }
                         
                    $item = Budgetpay::where('client_id', $request->clientid)->latest()->get();
                    
                    if($item)
                        {
                            foreach($item as $itemadvance)
                                {  
                                $itemadvancetotalbudget =  $request->totalbudget;
        
                                $totaladvcance = $itemadvance->adv_amt_rcvd;
        
                                $remainingtotal = $itemadvancetotalbudget - $totaladvcance;
        
        
                                $itemadvance->totalbudget = $itemadvancetotalbudget;
        
                                $itemadvance->remainig_balance = $remainingtotal;
        
                                // $itemadvance->save();
        
                                //$itemadvance->adv_amt_rcvd = $request->advanceamount;
                               // $itemadvance->save();
                            }
                        }
    
                    
                    $items = Budgetpay::where('client_id', $request->clientid)->latest()->first(); 
                    
                    
                    if($items)
                    {
                         
                        $totalbudget = $items->remainig_balance;
                        $advanceamount = $request->advanceamount;
                        
                        
                    }
                    else
                    {
                        
                        $totalbudget = $request->totalbudget;
                        
                        $advanceamount = $request->advanceamount;
                        
                        
                    }
                    
                    $remainingbalance = $totalbudget - $advanceamount;
                    
                    
                    
                    $budgetpay = new Budgetpay();
                            
                    $budgetpay->client_id = $request->clientid;
                    $budgetpay->totalbudget = $request->totalbudget;
                    $budgetpay->adv_amt_rcvd = $request->advanceamount;
                    $budgetpay->adv_amt_date = $request->advancedate; 
                    $budgetpay->remainig_balance = $remainingbalance; 
                    $budgetpay->due_date = $request->nextduedate; 
                    if($budgetpay->save())
                    {
                         return response()->json([
                                'message' => uiFast('Payment details updated'),
                                'status' => '1',
                                'data' => $budgetpay,
                                'user_role' => $user_role,
                                'logged_in_user' => $user_details,
                                'base_url' => 'https://planawedding.in/storage/',
                            ], 201);
                    }
                    else
                    {
                        return response()->json([
                            'message' => uiFast('Issues in adding payment'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 503);
                    } 
                }
            } 
            else 
            {
                return response()->json([
                    'message' => uiFast('User not found'),
                    'status' => '0',
                    'data' => [],
                    'user_role' => "",
                    'logged_in_user' => [],
                ], 401);
            }
        } 
