    public function guideaddindividualpageitineary(Request $request)
        {
            $token = $request->header('Authorization');
            $user  = $this->getuser($token);
        
            if ($user)
            {
                $today     = date("d-m-y-his");
                $todaydate = date("d/m/Y");
        
                $user_details = [
                    'name' => $user->name,
                    'email' => $user->email,
                    'mobile' => $user->mobile,
                    'business_name' => $user->business_name
                ];
        
                $useraccess = $this->chkuseraccess($token);
                $user_role  = $useraccess['role'];
        
                $rules = [
                    'itineary_type'     => 'required',
                    'itenary_client_id' => 'required'
                ];
        
                $validator = Validator::make($request->all(), $rules);
        
                if ($validator->fails())
                {
                    return response()->json([
                        'message' => $validator->messages(),
                    ]);
                }
        
                /* ---------------- INPUTS ---------------- */
        
                $typeitineray = $request->itineary_type;
                $customerid   = $request->itenary_client_id;
        
                $chektimeline = Timeline::where('client_itineray_id',$customerid)->latest()->first();
        
                if(!$chektimeline)
                {
                    $chektimeline = new Timeline();
                    $chektimeline->customer_id       = $customerid;
                    $chektimeline->client_itineray_id = $customerid;
                }
        
                /* ---------------- SECTION BUILDER ---------------- */
        
                $buildSection = function($itemsRaw)
                {
                    if(empty($itemsRaw)) return null;
        
                    $itemsRaw = substr($itemsRaw, 0, -1);
                    $itemsRaw = explode("#",$itemsRaw);
        
                    if(count(array_filter($itemsRaw)) == 0) return null;
        
                    $items = [];
                    $index = 1;
        
                    foreach($itemsRaw as $row)
                    {
                        $row = explode("^",$row);
        
                        $originalTitle = $row[0] ?? '';
        
                        $items[$index] = [
                            'rowtitle_value'   => $originalTitle,
                            'rowtitle_display' => uiFast($originalTitle),
        
                            'iconimage'   => $row[1] ?? '',
                            'hours'       => $row[2] ?? '',
                            'seconds'     => $row[3] ?? '',
                            'timeset'     => $row[4] ?? '',
                            'description' => $row[8] ?? '',
                            'eve_date'    => $row[9] ?? '',
                            'hihlights'   => $row[10] ?? 'no'
                        ];
        
                        $index++;
                    }
        
                    return json_encode($items);   // ✅ CRITICAL FIX
                };
        
                /* ---------------- BUILD ALL SECTIONS ---------------- */
        
                $chektimeline->customer_day_before_wedding =
                    $buildSection($request->listitems);
        
                $chektimeline->customer_wedding_day =
                    $buildSection($request->listitemswed);
        
                $chektimeline->customer_reception_day =
                    $buildSection($request->listitemsrecep);
        
                $chektimeline->customer_sangeeth_day =
                    $buildSection($request->listitemssangeeth);
        
                $chektimeline->customer_home_day =
                    $buildSection($request->listitemshome);
        
                /* ---------------- META ---------------- */
        
                $chektimeline->customer_generated_at   = time();
                $chektimeline->customer_generated_date = $todaydate;
                $chektimeline->customer_itineray       = $typeitineray;
        
                /* ---------------- SAVE ---------------- */
        
                if($chektimeline->save())
                {
                    /* ✅ DECODE FOR CLEAN RESPONSE */
        
                    $chektimeline->customer_day_before_wedding =
                        json_decode($chektimeline->customer_day_before_wedding, true);
        
                    $chektimeline->customer_wedding_day =
                        json_decode($chektimeline->customer_wedding_day, true);
        
                    $chektimeline->customer_reception_day =
                        json_decode($chektimeline->customer_reception_day, true);
        
                    $chektimeline->customer_sangeeth_day =
                        json_decode($chektimeline->customer_sangeeth_day, true);
        
                    $chektimeline->customer_home_day =
                        json_decode($chektimeline->customer_home_day, true);
        
                    return response()->json([
                        'message' => uiFast('Itineary created successfully'),
                        'status'  => '1',
                        'data'    => $chektimeline,
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
        
                return response()->json([
                    'message' => uiFast('Error In Itineary Creation'),
                    'status'  => '0',
                ], 503);
            }
        
            return response()->json([
                'message' => uiFast('User not found'),
                'status'  => '0',
            ], 401);
        }


