        public function externalleads(Request $request)
            {
                $token = $request->header('Authorization');
                $user = $this->getuser($token); 
                
                if($user) 
                {
                    $user_details = [
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name' => $user->business_name
                    ];
                    
                    $useraccess = $this->checkeditaccess($token);
                    $user_role = $useraccess['role'];
                    $user_access_array = $useraccess['access_array'];
                    
                    if($user->team_id == null)
                    {
                        $team_members = User::where('team_id',$user->id)
                            ->where('is_active',1)
                            ->select('id','name')
                            ->get()
                            ->toArray();
                    }
                    else
                    {
                        $team_members = User::where('team_id',$user->team_id)
                            ->where('is_active',1)
                            ->select('id','name')
                            ->get()
                            ->toArray();
                    }
            
                    $search   = $request->search;
                    $paginate = $request->paginate;
                    $allowsearch = !empty($search);
            
                    $page_heading = ['show' => 1,'name' => uiFast('External leads')];
                    $pagecontent  = ['show' => 1,'name' => uiFast('Upload your other leads from other sources')];
            
                    if($user_role == 'admin' || $user_role == 'partner admin')
                    {
                        $users = User::where('team_id',$user->id)
                            ->select('id')
                            ->get()
                            ->pluck('id')
                            ->toArray();
            
                        array_push($users, $user->id);
                        
                        $other_leads = OtherLead::select(
                            'other_leads.*',
                            'general_leads_remarks.id as general_leads_remarks_id',
                            'general_leads_remarks.user_id as general_leads_remarks_user_id',
                            'general_leads_remarks.new_noteremarks',
                            'general_leads_remarks.remarks',
                            'general_leads_remarks.status',
                            'general_leads_remarks.followup',
                            'general_leads_remarks.managed_by',
                            'general_leads_remarks.follow_done',
                            'general_leads_remarks.tentative_budget',
                            'general_leads_remarks.actual_budget'
                        )
                        ->whereIn('other_leads.user_id', $users)
                        ->leftJoin("general_leads_remarks","other_leads.id","=","general_leads_remarks.other_leads_id")
                        ->orderby('other_leads.id','desc')
                        ->when($allowsearch, function ($query) use ($search) {
                            $query->where(function($q) use ($search){
                                $q->where('name', 'like', '%'.$search.'%')
                                  ->orWhere('email', 'like', '%'.$search.'%')
                                  ->orWhere('mobile', 'like', '%'.$search.'%')
                                  ->orWhere('sourcefrom', 'like', '%'.$search.'%');
                            });
                        });
            
                        $other_leads = ($paginate == "false") 
                            ? $other_leads->get() 
                            : $other_leads->paginate(10);
            
                        // ✅ PERFORMANCE CACHE 🚀
                        $sourceCache = [];
                        $nameCache   = [];
            
                        if ($paginate != "false") {
            
                            $other_leads->getCollection()->transform(function ($lead) use (&$sourceCache, &$nameCache) {
            
                                if (!isset($sourceCache[$lead->sourcefrom])) {
                                    $sourceCache[$lead->sourcefrom] = translateLeadSourceSmart($lead->sourcefrom);
                                }
            
                                if (!isset($nameCache[$lead->name])) {
                                    $nameCache[$lead->name] = translateNameSmart($lead->name);
                                }
            
                                if (!isset($nameCache[$lead->reference_name])) {
                                    $nameCache[$lead->reference_name] = translateNameSmart($lead->reference_name);
                                }
            
                                // ✅ NAME
                               /* $lead->name_value = $lead->name;*/
                                $lead->name_display_text = $nameCache[$lead->name];
            
                                // ✅ SOURCE
                                /*$lead->sourcefrom_value = $lead->sourcefrom;*/
                                $lead->sourcefrom_display_text = $sourceCache[$lead->sourcefrom];
            
                                // ✅ REFERENCE NAME
                                /*$lead->reference_name_value = $lead->reference_name;*/
                                $lead->reference_name_display_text = $nameCache[$lead->reference_name];
            
                                return $lead;
                            });
            
                        } else {
            
                            $other_leads = $other_leads->map(function ($lead) use (&$sourceCache, &$nameCache) {
            
                                if (!isset($sourceCache[$lead->sourcefrom])) {
                                    $sourceCache[$lead->sourcefrom] = translateLeadSourceSmart($lead->sourcefrom);
                                }
            
                                if (!isset($nameCache[$lead->name])) {
                                    $nameCache[$lead->name] = translateNameSmart($lead->name);
                                }
            
                                if (!isset($nameCache[$lead->reference_name])) {
                                    $nameCache[$lead->reference_name] = translateNameSmart($lead->reference_name);
                                }
            
                                /*$lead->name_value = $lead->name;*/
                                $lead->name_display_text = $nameCache[$lead->name];
            
                                /*$lead->sourcefrom_value = $lead->sourcefrom;*/
                                $lead->sourcefrom_display_text = $sourceCache[$lead->sourcefrom];
            
                                /*$lead->reference_name_value = $lead->reference_name;*/
                                $lead->reference_name_display_text = $nameCache[$lead->reference_name];
            
                                return $lead;
                            });
                        }
                        
                        return response()->json([
                            'message' => uiTranslate('Other Leads Listing'),
                            'status'  => '1',
            
                            // ✅ RESTORED (YOU WANTED THIS)
                            'page_heading' => [
                                'show' => 1,
                                'name' => $page_heading['name']
                            ],
            
                            'page_content' => [
                                'show' => 1,
                                'name' => $pagecontent['name']
                            ],
            
                            'data' => $other_leads,
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                            'team_members' => $team_members,
                            'base_url' => 'https://planawedding.in/storage/',
                            'page_name' => 'External Leads',
                        ], 200);
                    }
                    else
                    {
                        return response()->json([
                            'message' => uiTranslate('User do not have access'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                            'team_members' => [],
                            'page_name' => 'External Leads',
                        ], 401);
                    }
                } 
                else 
                {
                    return response()->json([
                        'message' => uiTranslate('User not found'),
                        'status' => '0',
                        'data' => [],
                        'user_role' => "",
                        'logged_in_user' => [],
                        'team_members' => [],
                        'page_name' => "",
                    ], 401);
                }
            }

