                        'quote-sent' => "Quote Sent",
                        'negotiation' => "Negotiation",
                        'event-confirmed' => "Event Confirmed",
                        'lost' => "Lost",
                        'not-responding' => "Not Responding",
                        'no-requirement' => "No Requirement",
                        'date-not-confirmed' => "Date Not Confirmed",
                        'venue-not-finalised' => "Venue Not Finalised",
                        'meeting-yet-to-be-confirmed' => "Meeting Yet to be Confirmed",
                        'wedding-confirmed' => "Wedding Confirmed",
                        'wedding-completed' => "Wedding Completed",
                        'on-hold' => "On Hold",
                    ];
                    
                    if(empty($item_id))
                    {
                        return response()->json([
                            'message' => uiFast('Lead id is mandatory'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 400);
                    }
                    
                    if($user_role == 'admin' || $user_role == 'partner admin')
                    {
                        $users = User::where('team_id',$user->id)
                            ->pluck('id')
                            ->toArray();
            
                        array_push($users, $user->id);
            
                        $team_members_array = User::where('team_id',$user->id)
                            ->select('id','name')
                            ->get()
                            ->toArray();
            
                        $other_leads = OtherLead::where('other_leads.id',$item_id)
                            ->whereIn('other_leads.user_id', $users)
                            ->leftJoin("general_leads_remarks","other_leads.id","=","general_leads_remarks.other_leads_id")
                            ->select(
                                'other_leads.id',
                                'other_leads.team_id',
                                'other_leads.name',
                                'other_leads.email',
                                'other_leads.mobile',
                                'other_leads.sourcefrom',
                                'other_leads.reference_name',
                                'other_leads.reference_mobile',
                                'general_leads_remarks.remarks',
                                'general_leads_remarks.new_noteremarks',
                                'general_leads_remarks.followup',
                                'general_leads_remarks.managed_by',
                                'general_leads_remarks.follow_done',
                                'general_leads_remarks.status'
                            )
                            ->first();
            
                        // ✅ TRANSLATE LEAD ONLY 🚀
                        if ($other_leads) {
            
                            $other_leads->name_display_text = translateNameSmart($other_leads->name);
                            $other_leads->sourcefrom_display_text = translateLeadSourceSmart($other_leads->sourcefrom);
                            $other_leads->reference_name_display_text = translateNameSmart($other_leads->reference_name);
                            $other_leads->remarks_display_text = translateLongText($other_leads->remarks);
            
                            $other_leads->status_display_text =
                                uiFast($statuses[$other_leads->status] ?? $other_leads->status);
                        }
            
                        // ✅ STATUSES STRUCTURE 🎯
                        $statuses_output = [];
            
                        foreach ($statuses as $key => $value) {
            
                            $statuses_output[$key] = [
                                'statuses_value' => $value,
                                'statuses_display_text' => uiFast($value),
                            ];
                        }
            
                        return response()->json([
                            'message' => uiFast('Other Leads Listing'),
                            'status' => '1',
                            'data' => $other_leads,
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                            'statuses' => $statuses_output,
            
                            // ✅ UNTOUCHED 😎
                            'team_members' => $team_members_array,
            
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 200);
                    }
                    else
                    {
                        return response()->json([
                            'message' => uiFast('User do not have access'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 401);
                    }
                } 
                else 
                {
                    return response()->json([
                        'message' => uiFast('User not found'),
                        'status' => '0',
                        'data' => [],
                        'user_role' => "",
                        'logged_in_user' => [],
                    ], 401);
                }
            }

        public function editexternalleadsingle(Request $request)
            {
