        public function addotherleads(Request $request)
            {
                $token = $request->header('Authorization');
                $user = $this->getuser($token);
                
                if($user) 
                {
                    $user_details = [
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name' => $user->business_name
                    ];
                    
                    $useraccess = $this->chkuseraccess($token);
                    $user_role = $useraccess['role'];
                    $user_access_role = $useraccess['useraccess'];
                    
                    $rules = array(
                        'name' => 'required',
                        'email' => 'required|email',
                        'mobile' => 'required|numeric',
                        'location' => 'required',
                        'weddingdate_select' => 'required',
                        'wedding_date' => "required_if:weddingdate_select,==,dateyes",
                        'wedding_approx' => "required_if:weddingdate_select,==,dateno",
                        'sourcefrom' => 'required|in:Instagram,Just Dial,Sulekha,Indiamart,Wedmegood,Wedding wire,Google,Wedding Bazaar,Reference',
                        "reference_name" => "required_if:sourcefrom,==,Reference",
                        "reference_mobile" => "required_if:sourcefrom,==,Reference",
                    );
            
                    $error = Validator::make($request->all(), $rules);
            
                    if($error->fails())
                    {
                        return response()->json([
                            'message' => uiFast('Validation failed'),
                            'status'  => '0',
                            'errors'  => $error->errors()->all()
                        ], 422);
                    }
                    else
                    {
                        if($user_role == 'admin' || $user_role == 'partner admin')
                        {
                            $other_lead = new OtherLead();
                            
                            $other_lead->user_id = $user->id;
