        public function editotherleadsingle(Request $request)
            {
                $token = $request->header('Authorization');
                $user = $this->getuser($token);
                 
                if($user) 
                {
                    $user_details = [
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name' => $user->business_name
                    ];
                    
                    $useraccess = $this->chkuseraccess($token);
                    $user_role = $useraccess['role'];
                    $user_access_role = $useraccess['useraccess'];
                    
                    $item_id = $request->id;
                    
                    if(empty($item_id))
                    {
                        return response()->json([
                            'message' => uiFast('Lead id is mandatory'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 400);
                    }
                    
                    $rules = array(
                        'name' => 'required',
                        'email' => 'required|email',
                        'mobile' => 'required|numeric',
                        'location' => 'required',
                        'weddingdate_select' => 'required',
                        'wedding_date' => "required_if:weddingdate_select,==,dateyes",
                        'wedding_approx' => "required_if:weddingdate_select,==,dateno",
                        'sourcefrom' => 'required|in:Instagram,Just Dial,Sulekha,Indiamart,Wedmegood,Wedding wire,Google,Wedding Bazaar,Reference',
                        "reference_name" => "required_if:sourcefrom,==,Reference",
                        "reference_mobile" => "required_if:sourcefrom,==,Reference",
                    );
                    
                    $validator = Validator::make($request->all(), $rules);
                    
                    if ($validator->fails()) 
                    {
                        return response()->json([
                            'message' => uiFast('Validation failed'),
                            'status'  => '0',
                            'errors'  => $validator->errors()->all()
                        ], 422);
                    } 
                    else
                    {
                        $generallead = GeneralLead::where('id',$item_id)->first();
                        
                        if($generallead)
                        {
                            $allow_edit = true;
                            
                            if($allow_edit)
                            {
                                $generallead->name = $request->name;
                                $generallead->email = $request->email;
                                $generallead->mobile = $request->mobile;
                                $generallead->wedding_datefixed = $request->weddingdate_select;
                                $generallead->event_date = $request->wedding_date;
                                $generallead->approx_wedding = $request->wedding_approx;
                                $generallead->city = $request->location;
                                $generallead->event_location = $request->location;
                                $generallead->leadsource = $request->sourcefrom;
                                $generallead->src_refer_name = $request->reference_name;
                                $generallead->src_refer_mobile = $request->reference_mobile;
            
                                if($generallead->save())
                                {
                                    /* ✅ RESPONSE TRANSLATION ONLY 🚀 */
            
                                    $generallead->name_display_text = translateNameSmart($generallead->name);
                                    $generallead->sourcefrom_display_text = translateLeadSourceSmart($generallead->leadsource);
                                    $generallead->reference_name_display_text = translateNameSmart($generallead->src_refer_name);
                                    $generallead->location_display_text = translateVenueLocation($generallead->event_location);
            
                                    /* ✅ DESCRIPTION FIELDS (SAFE LOOP) */
            
                                    foreach ($generallead->getAttributes() as $key => $value) 
                                    {
                                        if (!$value) continue;
            
                                        // ✅ Prevent duplication
                                        if (str_contains($key, 'display_text')) continue;
            
                                        if (str_contains($key, 'description')) 
                                        {
                                            $generallead->{$key . '_display_text'} = translateLongText($value);
                                        }
                                    }
            
                                    /* ✅ CATEGORY FIELDS (SAFE LOOP) */
            
                                    foreach ($generallead->getAttributes() as $key => $value) 
                                    {
                                        if (!$value) continue;
            
                                        // ✅ Prevent duplication
                                        if (str_contains($key, 'display_text')) continue;
            
                                        if (str_contains($key, 'category')) 
                                        {
                                            $generallead->{$key . '_display_text'} = translateCategorySmart($value);
                                        }
                                    }
            
                                    /* ✅ LEAD TYPE FIELDS */
            
                                    foreach ($generallead->getAttributes() as $key => $value) 
                                    {
                                        if (!$value) continue;
            
                                        // ✅ Prevent duplication
                                        if (str_contains($key, 'display_text')) continue;
            
                                        if (str_contains($key, 'lead_type')) 
                                        {
                                            $generallead->{$key . '_display_text'} = uiFast($value);
                                        }
                                    }
            
                                    /* ✅ CITY / STATE */
                                        
                                    if (!empty($generallead->package_type))  
                                    {
                                        $generallead->package_type_display_text = uiFast($generallead->package_type);
                                    }
                                    if (!empty($generallead->city)) {
                                        $generallead->city_display_text = translateCity($generallead->city);
                                    }
            
                                    if (!empty($generallead->state_name)) {
                                        $generallead->state_name_display_text = fixTamilStateEnding(translateState($generallead->state_name));
                                    }
            
                                    if (!empty($generallead->state_capital)) {
                                        $generallead->state_capital_display_text = translateCity($generallead->state_capital);
                                    }
            
                                    /* ✅ WEDDING TYPE */
            
                                    if (!empty($generallead->wedding_type)) {
                                        $generallead->wedding_type_display_text = uiFast($generallead->wedding_type);
                                    }
            
                                    /* ✅ ADDRESS */
            
                                    if (!empty($generallead->address)) {
                                        $generallead->address_display_text = translateAddressSafe($generallead->address);
                                    }
            
                                    return response()->json([
                                        'message' => uiFast('Lead Updated'),
                                        'status' => '1',
                                        'data' => $generallead,
                                        'user_role' => $user_role,
                                        'logged_in_user' => $user_details,
                                        'base_url' => 'https://planawedding.in/storage/',
                                    ], 200);  
                                }
                                else
                                {
                                    return response()->json([
                                        'message' => uiFast('Issues in Lead update'),
                                        'status' => '0',
                                        'data' => [],
                                        'user_role' => $user_role,
                                        'logged_in_user' => $user_details,
                                        'base_url' => 'https://planawedding.in/storage/',
                                    ], 304);
                                } 
                            }
                            else
                            {
                                return response()->json([
                                    'message' => uiFast('User not authorised to edit this lead'),
                                    'status' => '0',
                                    'data' => $generallead,
                                    'user_role' => $user_role,
                                    'logged_in_user' => $user_details,
                                    'base_url' => 'https://planawedding.in/storage/',
                                ], 401);
                            }
                        }
                        else
                        {
                            return response()->json([
                                'message' => uiFast('Lead not found'),
                                'status' => '0',
                                'data' => [],
                                'user_role' => $user_role,
                                'logged_in_user' => $user_details,
