        public function getmypreferences(Request $request)
            {
                $token = $request->header('Authorization');
                $user = $this->getuser($token);
                
                if($user) 
                {
                    $user_details = [
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name' => $user->business_name
                    ];
                    
                    $useraccess = $this->checkeditaccess($token);
                    $user_role = $useraccess['role'];
                    
                    if($user_role == 'partner admin')
                    {
                        $userpartner = UserPartner::where('userid',$user->id)->first();
            
                        if ($userpartner && !empty($userpartner->service_city))
                        {
                            $cities = json_decode($userpartner->service_city, true);
            
                            if (is_array($cities))
                            {
                                foreach ($cities as $index => $row)
                                {
                                    $city = trim($row['city'] ?? '');
            
                                    $cities[$index] = [
                                        'city_value' => $city,
                                        'city_display_text' => translateCity($city)
                                    ];
                                }
            
                                // ✅ overwrite ONLY for response
                                $userpartner->service_city = $cities;
                            }
                        }
                        
                        return response()->json([
                            'message' => uiFast('My Preferences'),
                            'status' => '1',
                            'data' => $userpartner,
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                            'base_url' => 'https://planawedding.in/storage/',
                        ], 200);
                    }
                    else
                    {
                        return response()->json([
                            'message' => uiFast('User do not have access'),
                            'status' => '0',
                            'data' => [],
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 401);
                    }
                } 
                else 
                {
                    return response()->json([
                        'message' => uiFast('User not found'),
                        'status' => '0',
                        'data' => [],
                        'user_role' => "",
                        'logged_in_user' => [],
                    ], 401);
                }
            }


        public function savemypreferencescities(Request $request)
            {
                $token = $request->header('Authorization');
                $user = $this->getuser($token);
                
                if($user) 
                {
                    $user_details = [
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name' => $user->business_name
                    ];
                    
                    $useraccess = $this->checkeditaccess($token);
                    $user_role = $useraccess['role'];
                    
                    $rules = [
                        'cities' => 'required',
                    ];
                    
                    $validator = Validator::make($request->all(), $rules);
                    
                    if ($validator->fails()) 
                    {
                        return response()->json([
                            'message' => uiFast('Validation failed'),
                            'status'  => '0',
                            'errors'  => $validator->errors()->all()
                        ], 422);
                    } 
                    else
                    {
                        if($user_role == 'partner admin')
                        {
                            $citiesvalue = $request->cities;
                            $service_cities = NULL;
            
                            if(!empty($citiesvalue))
                            {
                                $cities = explode(",", $citiesvalue);
                                $itemCount = count($cities);
            
                                $items = [];
                                $j = 0;
            
                                if(count(array_filter($cities)) != 0) 
                                {
                                    for($i = 1; $i <= $itemCount; $i++)
                                    {
                                        $oneitem = $cities[$j];
                                        $oneitem = explode("^", $oneitem);
            
                                        $items[$i]['city'] = trim($oneitem[0] ?? '');
            
                                        $j++;
                                    }
                                }
            
                                $service_cities = json_encode($items); 
                            }
            
                            $userpartner = UserPartner::firstOrNew(['userid' => $user->id]);
            
                            $userpartner->service_city = $service_cities;  
                            
                            if($userpartner->save())
                            {
                                /* ✅ RESPONSE TRANSLATION ONLY 🚀 */
            
                                if (!empty($userpartner->service_city))
                                {
                                    $cities = json_decode($userpartner->service_city, true);
            
                                    if (is_array($cities))
                                    {
                                        foreach ($cities as $index => $row)
                                        {
                                            $city = trim($row['city'] ?? '');
            
                                            $cities[$index] = [
                                                'city_value' => $city,
                                                'city_display_text' => translateCity($city)
                                            ];
                                        }
            
                                        // overwrite ONLY for response
                                        $userpartner->service_city = $cities;
                                    }
                                }
            
                                return response()->json([
                                    'message' => uiFast('My preferences cities updated'),
                                    'status' => '1',
                                    'data' => $userpartner,
                                    'user_role' => $user_role,
                                    'logged_in_user' => $user_details,
                                    'base_url' => 'https://planawedding.in/storage/',
                                ], 200);
                            }
                            else
                            {
                                return response()->json([
                                    'message' => uiFast('My preferences cities not updated'),
                                    'status' => '0',
                                    'data' => $userpartner,
                                    'user_role' => $user_role,
                                    'logged_in_user' => $user_details,
                                    'base_url' => 'https://planawedding.in/storage/',
                                ], 200);
                            }
                        }
                        else
                        {
                            return response()->json([
                                'message' => uiFast('User do not have access'),
                                'status' => '0',
                                'data' => [],
                                'user_role' => $user_role,
                                'logged_in_user' => $user_details,
                            ], 401);
                        }
                    }
                } 
                else 
                {
                    return response()->json([
                        'message' => uiFast('User not found'),
                        'status' => '0',
                        'data' => [],
                        'user_role' => "",
                        'logged_in_user' => [],
                    ], 401);
                }
            }
        
        public function savemypreferencesdates(Request $request)
            {
                $token = $request->header('Authorization');
                $user = $this->getuser($token);
                
                if($user) 
                {
                    $user_details = [
                        'name' => $user->name,
                        'email' => $user->email,
                        'mobile' => $user->mobile,
                        'business_name' => $user->business_name
                    ];
                    
                    $useraccess = $this->checkeditaccess($token);
                    $user_role = $useraccess['role'];
                    
                    $rules = [
                        'datevalaues' => 'required',
                    ];
                    
                    $validator = Validator::make($request->all(), $rules);
                    
                    if ($validator->fails()) 
                    {
                        return response()->json([
                            'message' => uiFast('Validation failed'),
                            'status'  => '0',
                            'errors'  => $validator->errors()->all()
                        ], 422);
                    } 
                    else
                    {
                        if($user_role == 'partner admin')
                        {
                            $datevalaues = $request->datevalaues;
                            $service_dates = NULL;
            
                            if(!empty($datevalaues))
                            {
                                $dates = explode(",", $datevalaues);
                                $itemCount = count($dates);
            
                                $items = [];
                                $j = 0;
            
                                if(count(array_filter($dates)) != 0) 
                                {
                                    for($i = 1; $i <= $itemCount; $i++)
                                    {
                                        $oneitem = $dates[$j];
                                        $oneitem = explode("^", $oneitem);
            
                                        $items[$i]['blockdate'] = $oneitem[0]; 
                                        $j++;
                                    }
                                }
            
                                $service_dates = json_encode($items); 
                            }
            
                            $userpartner = UserPartner::firstOrNew(['userid' => $user->id]);
                            $userpartner->blocked_dates = $service_dates;  
                            
                            if($userpartner->save())
                            {
                                /* ✅ RESPONSE CLEANUP 🚀 */
            
                                // BLOCKED DATES → NO TRANSLATION
                                if (!empty($userpartner->blocked_dates))
                                {
                                    $dates = json_decode($userpartner->blocked_dates, true);
            
                                    if (is_array($dates))
                                    {
                                        foreach ($dates as $index => $row)
                                        {
                                            $dates[$index] = [
                                                'blockdate_value' => trim($row['blockdate'] ?? '')
                                            ];
                                        }
            
                                        $userpartner->blocked_dates = $dates;
                                    }
                                }
            
                                // SERVICE CITY → TRANSLATE ONLY IF EXISTS ✅
                                if (!empty($userpartner->service_city))
                                {
                                    $cities = json_decode($userpartner->service_city, true);
            
                                    if (is_array($cities))
                                    {
                                        foreach ($cities as $index => $row)
                                        {
                                            $city = trim($row['city'] ?? '');
            
                                            $cities[$index] = [
                                                'city_value' => $city,
                                                'city_display_text' => translateCity($city)
                                            ];
                                        }
            
                                        $userpartner->service_city = $cities;
                                    }
                                }
            
                                return response()->json([
                                    'message' => uiFast('My preferences dates updated'),
                                    'status' => '1',
                                    'data' => $userpartner,
                                    'user_role' => $user_role,
                                    'logged_in_user' => $user_details,
                                    'base_url' => 'https://planawedding.in/storage/',
                                ], 200);
                            }
                            else
                            {
                                return response()->json([
                                    'message' => uiFast('My preferences dates not updated'),
                                    'status' => '0',
                                    'data' => [],
                                    'user_role' => $user_role,
                                    'logged_in_user' => $user_details,
                                ], 200);
                            }
                        }
                        else
                        {
                            return response()->json([
                                'message' => uiFast('User do not have access'),
                                'status' => '0',
                                'data' => [],
                                'user_role' => $user_role,
                                'logged_in_user' => $user_details,
                            ], 401);
                        }
                    }
                } 
                else 
                {
                    return response()->json([
                        'message' => uiFast('User not found'),
                        'status' => '0',
                        'data' => [],
                        'user_role' => "",
                        'logged_in_user' => [],
                    ], 401);
                }
            }


