        public function hirecrewlistings_1(Request $request)
            {
                $token = $request->header('Authorization');
                $user  = $this->getuser($token);
            
                if (!$user) {
                    return response()->json([
                        'message' => uiFast('User not found'),
                        'status'  => '0',
                        'data'    => [],
                        'user_role' => "",
                        'logged_in_user' => [],
                    ], 401);
                }
            
                $user_details = [
                    'name' => $user->name,
                    'email' => $user->email,
                    'mobile' => $user->mobile,
                    'business_name' => $user->business_name
                ];
            
                $useraccess = $this->checkeditaccess($token);
                $user_role  = $useraccess['role'];
            
                /* ✅ Crew Static Config */
                $crewData = $this->getHireCrewData();
            
                /* ✅ Transform + Translation */
                foreach ($crewData as $gender => &$sessions) {
            
                    foreach ($sessions as $session => &$roles) {
            
                        foreach ($roles as &$roleData) {
            
                            /* Role */
                            $roleData['role_value'] = $roleData['role'];
                            $roleData['role_display_text'] = uiFast($roleData['role']);
                            unset($roleData['role']);
            
                            /* Prices */
                            foreach ($roleData['prices'] as $city => &$price) {
            
                                $price = [
                                    'city_value' => $city,
                                    'city_display_text' => translateVenueLocation($city),
                                    'price' => $price
                                ];
                            }
                        }
            
                        /* Session Translation */
                        $translatedSession = [
                            'session_value' => $session,
                            'session_display_text' => uiFast($session),
                            'roles' => $roles
                        ];
            
                        $sessions[$session] = $translatedSession;
                       //unset($sessions[$session]['roles']); // cleanup safeguard
                    }
                }
            
                return response()->json([
                    'message' => uiFast('Hire Crew Listings'),
                    'status'  => '1',
            
                    'page_title' => uiFast('Hire Crew'),
            
                    'page_description' => uiFast(
                        'Hiring event crew in selected live cities, our trusted partners will manage all deliverables seamlessly end-to-end'
                    ),
            
                    'hire_role' => $crewData,
            
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
            
                ], 200);
            }
            
        public function hirecrewlistings(Request $request)
            {
                $token = $request->header('Authorization');
                $user  = $this->getuser($token);
            
                if (!$user) {
                    return response()->json([
                        'message' => uiFast('User not found'),
                        'status'  => '0',
                        'data'    => [],
                        'user_role' => "",
                        'logged_in_user' => [],
                    ], 401);
                }
            
                $user_details = [
                    'name' => $user->name,
                    'email' => $user->email,
                    'mobile' => $user->mobile,
                    'business_name' => $user->business_name
                ];
            
                $useraccess = $this->checkeditaccess($token);
                $user_role  = $useraccess['role'];
            
                /* ✅ Crew Static Config */
                $crewData = $this->getHireCrewData();
            
                /* ✅ Transform + Translation */
                foreach ($crewData as $gender => &$sessions) {
            
                    foreach ($sessions as $session => &$roles) {
            
                        foreach ($roles as &$roleData) {
            
                            /* Role */
                            $roleData['role_value'] = $roleData['role'];
                            $roleData['role_display_text'] = uiFast($roleData['role']);
                            unset($roleData['role']);
            
                            /* Prices */
                            foreach ($roleData['prices'] as $city => &$price) {
            
                                $price = [
                                    'city_value' => $city,
                                    'city_display_text' => translateVenueLocation($city),
                                    'price' => $price
                                ];
                            }
                        }
            
                        /* Session Translation */
                        $translatedSession = [
                            'session_value' => $session,
                            'session_display_text' => uiFast($session),
                            'roles' => $roles
                        ];
            
                        $sessions[$session] = $translatedSession;
                    }
                }
            
                /* ✅ Event Totals Subquery */
                $eventTotals = \DB::table('hire_role_requests')
                    ->selectRaw('hire_event_id, SUM(grand_total) as event_total_amount, MAX(request_status) as request_status')
                    ->groupBy('hire_event_id');
            
                /* ✅ Fetch User Events (Latest First) */
                $events = \DB::table('hire_event_details as hed')
                    ->leftJoinSub($eventTotals, 'totals', function ($join) {
                        $join->on('hed.id', '=', 'totals.hire_event_id');
                    })
                    ->where('hed.user_id', $user->id)
                    ->orderByDesc('hed.id')
                    ->get();
            
                /* ✅ Transform Events */
                $eventData = [];
            
                foreach ($events as $event) {
            
                    $eventData[] = [
                        'id' => $event->id,
                        'event_id' => $event->id,
            
                        'event_type' => $event->event_type,
                        'event_type_display_text' => uiFast($event->event_type),
            
                        'event_name' => $event->event_name,
                        'event_name_display_text' => transliterateTextKeepNumbers($event->event_name),
                        
                        
                        'event_city' => $event->event_city,
                        'event_city_display_text' => translateVenueLocation($event->event_city),
            
                        'event_from' => $event->event_from,
                        'event_to' => $event->event_to,
            
                        'event_status' => $event->event_status,
                        'event_status_display_text' => uiFast($event->event_status),
            
                        'request_generated' => ($event->request_generated == "1"),
            
                        'event_total_amount' => (float) ($event->event_total_amount ?? 0),
            
                        'request_status' => $event->request_status,
                        'request_status_display_text' => transliterateText($event->request_status),
                    ];
                }
            
                return response()->json([
                    'message' => uiFast('Hire Crew Listings'),
                    'status'  => '1',
            
                    'page_title' => uiFast('Hire Crew'),
            
                    'page_description' => uiFast(
                        'Hiring event crew in selected live cities, our trusted partners will manage all deliverables seamlessly end-to-end'
                    ),
            
                    'hire_role' => $crewData,
            
