                        'logged_in_user' => [],
                    ], 401);
                }
            
                $user_details = [
                    'name' => $user->name,
                    'email' => $user->email,
                    'mobile' => $user->mobile,
                    'business_name' => $user->business_name
                ];
            
                $useraccess = $this->checkeditaccess($token);
                $user_role  = $useraccess['role'];
            
                /* ✅ VALIDATION */
                $rules = [
                    'event_type' => 'required',
                    'event_name' => 'required',
                    'event_city' => 'required', 
                    'event_from' => 'required|date_format:d/m/Y',
                    'event_to'   => 'nullable|date_format:d/m/Y',

                ];
               
                $validator = Validator::make($request->all(), $rules);
            
                if ($validator->fails()) {
                    return response()->json([
                        'message' => uiFast('Validation failed'),
                        'status'  => '0',
                        'errors'  => $validator->errors()->all()
                    ], 422);
                }
                 
                 
                /* ✅ SAVE */
                $event = new HireEventDetail();
            
                // ✅ ALWAYS SESSION USER (SECURE 🔥)
                $event->user_id = $user->id;
            
                $event->event_type = $request->event_type;
                $event->event_name = $request->event_name;
                $event->event_city = $request->event_city;
            
                $event->event_from = $request->event_from;
                $event->event_to   = $request->event_to;
            
                $event->event_status = 'Open'; 
            
            
                $event->event_created_on = now()->format('d/m/Y H:i:s');
            
                if ($event->save()) {
            
                    /* ✅ RESPONSE TRANSLATION ONLY 😎 */
             
                    $event->event_type_display_text = uiFast($event->event_type);
             
                    $event->event_name_display_text = transliterateTextKeepNumbers($event->event_name);
             
                    $event->event_city_display_text = translateVenueLocation($event->event_city);
             
                    $event->event_from = $event->event_from;
             
                    if(!empty($event->event_to))
                    {
                        $event->event_to = $event->event_to;
                    }
                     
                    $event->event_status_display_text = transliterateText($event->event_status);
                    
                    $event->event_id = $event->id;
                    
                    /*
                        unset(
                            $event->event_type,
                            $event->event_name,
                            $event->event_city,
                            $event->event_from,
                            $event->event_to,
                            $event->event_status
                        );
                    */
            
                    return response()->json([
                        'message' => uiFast('Event details saved'),
                        'page_title' => uiFast('Hire Crew'),
                        'status'  => '1',
                        'data'    => $event,
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 201);
                }
            
                return response()->json([
                    'message' => uiFast('Event save failed'),
                    'page_title' => uiFast('Hire Crew'),
                    'status'  => '0',
                    'data'    => [],
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                ], 200);
            }


        public function gethireeventroles(Request $request)
            {
                $token = $request->header('Authorization');
                $user  = $this->getuser($token);
            
                if (!$user) {
                    return response()->json([
                        'message' => uiFast('User not found'),
                        'status'  => '0',
                        'data'    => [],
                        'user_role' => "",
                        'logged_in_user' => [],
                    ], 401);
                }
            
                $userContext = $this->buildUserContext($user, $token);
            
                /* ✅ Validation */
                $validator = Validator::make($request->all(), [
                    'event_id' => 'required|numeric'
                ]);
            
                if ($validator->fails()) {
                    return response()->json([
                        'message' => uiFast('Validation failed'),
                        'status'  => '0',
                        'errors'  => array_values($validator->errors()->all())
                    ] + $userContext, 422);
                }
            
                $event_id = $request->event_id;
            
                /* ✅ Fetch Event */
                $event = HireEventDetail::where('id', $event_id)->first();
            
                if (!$event) {
                    return response()->json([
                        'message' => uiFast('Event not found'),
                        'status'  => '0',
                        'data'    => []
                    ] + $userContext, 404);
                }
            
                /* ================= EVENT DATES ================= */
            
                $event_dates = [];
            
                if (!empty($event->event_from)) {
            
                    $from = \Carbon\Carbon::createFromFormat('d/m/Y', $event->event_from);
            
                    if (!empty($event->event_to)) {
            
                        $to = \Carbon\Carbon::createFromFormat('d/m/Y', $event->event_to);
            
                        while ($from->lte($to)) {
            
                            $value = $from->format('d/m/Y');
            
                            $event_dates[] = [
                                'event_date_value' => $value,
                                'event_date_display_text' => uiFast($from->format('M d, Y'))
                            ];
            
                            $from->addDay();
                        }
            
                    } else {
            
                        $value = $from->format('d/m/Y');
            
                        $event_dates[] = [
                            'event_date_value' => $value,
                            'event_date_display_text' => uiFast($from->format('M d, Y'))
                        ];
                    }
                }
            
                /* ================= CREW DATA ================= */
            
                $crewData = $this->getHireCrewData();
            
                $uniqueSessions = [];
                $uniqueRoles    = [];
            
                foreach ($crewData as $gender => &$sessions) {
            
                    foreach ($sessions as $session => &$roles) {
            
                        $uniqueSessions[$session] = [
                            'session_value' => $session,
                            'session_display_text' => uiFast($session)
                        ];
            
                        foreach ($roles as &$roleData) {
            
                            /* Roles List */
                            $uniqueRoles[$roleData['role']] = [
                                'role_value' => $roleData['role'],
                                'role_display_text' => uiFast($roleData['role'])
                            ];
            
                            /* Role Translation */
                            $roleData['role_value'] = $roleData['role'];
                            $roleData['role_display_text'] = uiFast($roleData['role']);
                            unset($roleData['role']);
            
                            /* Prices Translation */
                            foreach ($roleData['prices'] as $city => &$price) {
            
                                $price = [
                                    'city_value' => $city,
                                    'city_display_text' => translateVenueLocation($city),
                                    'price' => $price
                                ];
                            }
                        }
            
                        /* Session Structure */
                        $sessions[$session] = [
                            'session_value' => $session,
                            'session_display_text' => uiFast($session),
                            'roles' => $roles
                        ];
                    }
                }
            
                /* ================= RESPONSE ================= */
            
                return response()->json([
                    'message' => uiFast('Hire Event Roles'),
                    'status'  => '1',
            
                    'event_date'   => $event_dates,
                    'session_type' => array_values($uniqueSessions),
                    'role_type'    => array_values($uniqueRoles),
            
                    'hire_role'    => $crewData,
            
                ] + $userContext, 200);
            } 
          

        public function savehireroles_1(Request $request)
            {
                $token = $request->header('Authorization');
                $user  = $this->getuser($token);
            
                if (!$user) {
                    return response()->json([
                        'message' => uiFast('User not found'),
                        'status'  => '0',
                        'data'    => [],
                        'user_role' => "",
                        'logged_in_user' => [],
                    ], 401);
                }
            
                $user_details = [
                    'name' => $user->name,
                    'email' => $user->email,
                    'mobile' => $user->mobile,
                    'business_name' => $user->business_name
                ];
            
                $useraccess = $this->checkeditaccess($token);
                $user_role  = $useraccess['role'];
            
                /* ✅ VALIDATION */
                $validator = Validator::make($request->all(), [
                    'hire_event_id' => 'required|numeric',
                    'roles'         => 'required|array',
                ]);
            
                if ($validator->fails()) {
                    return response()->json([
                        'message' => uiFast('Validation failed'),
                        'status'  => '0',
                        'errors'  => $validator->errors()->all()
                    ], 422);
                }
            
                /* ✅ CHECK EVENT EXISTS */
                $event = HireEventDetail::where('id', $request->hire_event_id)->first();
            
                if (!$event) {
                    return response()->json([
                        'message' => uiFast('Invalid hire event'),
                        'status'  => '0',
                        'data'    => [],
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 422);
                }
            
                /* ✅ CREATE REQUEST */
                $hireRequest = HireRoleRequest::create([
                    'hire_event_id' => $request->hire_event_id,
                    'grand_total'   => 0
                ]);
            
                $grandTotal = 0;
                $savedRows  = [];
            
                foreach ($request->roles as $role) {
            
                    $maleCount  = intval($role['male_count'] ?? 0);
                    $malePrice  = intval($role['male_price'] ?? 0);
            
                    $femaleCount = intval($role['female_count'] ?? 0);
                    $femalePrice = intval($role['female_price'] ?? 0);
            
                    /* ✅ CALCULATIONS */
                    $maleTotal   = $maleCount * $malePrice;
                    $femaleTotal = $femaleCount * $femalePrice;
            
                    $subTotal = $maleTotal + $femaleTotal;
            
                    $grandTotal += $subTotal;
            
                    /* ✅ SAVE ROW */
                    $row = HireRoleRequestItem::create([
            
                        'hire_role_request_id' => $hireRequest->id,
            
                        'day_number'   => $role['day_number'] ?? null,
                        'event_date'   => $role['event_date'] ?? null,
            
                        'session_type' => $role['session_type'] ?? null,
                        'role_type'    => $role['role_type'] ?? null,
            
                        'male_count'   => $maleCount,
                        'male_price'   => $malePrice,
                        'male_total'   => $maleTotal,
                        'male_total_price' => $maleTotal,
            
                        'female_count' => $femaleCount,
                        'female_price' => $femalePrice,
                        'female_total' => $femaleTotal,
                        'female_total_price' => $femaleTotal,
            
                        'sub_total' => $subTotal,
                        'row_total' => $subTotal,
            
                    ]);
            
                    $savedRows[] = $row;
                }
            
                /* ✅ UPDATE GRAND TOTAL */
                $hireRequest->update([
                    'grand_total' => $grandTotal
                ]);
            
                /* ✅ UPDATE EVENT */
                HireEventDetail::where('id', $request->hire_event_id)
                    ->update(['request_generated' => "1"]);
            
                /* ✅ TRANSLATE RESPONSE */
                $translatedRows = collect($savedRows)->map(function ($row) {
            
                    if (!empty($row->session_type)) {
                        $row->session_type = $row->session_type;
                        $row->session_type_display_text = uiFast($row->session_type);
                        //unset($row->session_type);
                    }
            
                    if (!empty($row->role_type)) {
                        $row->role_type = $row->role_type;
                        $row->role_type_display_text = uiFast($row->role_type);
                        //unset($row->role_type);
                    }
            
                    return $row;
                });
            
                return response()->json([
                    'message' => uiFast('Hire roles saved successfully'),
                    'status'  => '1',
            
                    'grand_total' => $grandTotal,
            
                    'data' => $translatedRows->values(),
            
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
            
                ], 200);
            }
            
