                $user_role  = $useraccess['role'];
            
                /* ✅ CHECK EVENT */
                $event = HireEventDetail::where('id', $event_id)
                    ->where('user_id', $user->id)
                    ->first();
            
                if (!$event) {
                    return response()->json([
                        'message' => uiFast('Invalid event'),
                        'status'  => '0',
                        'data'    => [],
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 422);
                }
            
                /* ✅ FETCH REQUEST */
                $hireRequest = HireRoleRequest::where('hire_event_id', $event->id)->first();
            
                /* ✅ FETCH ITEMS */
                $items = [];
            
                if ($hireRequest) {
            
                    $items = HireRoleRequestItem::where('hire_role_request_id', $hireRequest->id)
                            ->orderBy('day_number')
                            ->get()
                            ->groupBy('day_number')
                            ->map(function ($dayRows, $dayNumber) {
                        
                                $firstRow = $dayRows->first();
                        
                                return [
                        
                                    'day_number' => $dayNumber,
                                    'event_date' => $firstRow->event_date,
                        
                                    /* ✅ Day Total 🔥 */
                                    'day_total' => (float) $dayRows->sum('sub_total'),
                        
                                    'sessions' => $dayRows->map(function ($row) {
                        
                                        return [
                        
                                            'id' => $row->id,
                                            'hire_role_request_id' => $row->hire_role_request_id,
                        
                                            'male_count' => $row->male_count,
                                            'male_price' => $row->male_price,
                                            'male_total' => $row->male_total,
                                            'male_total_price' => $row->male_total_price,
                        
                                            'female_count' => $row->female_count,
                                            'female_price' => $row->female_price,
                                            'female_total' => $row->female_total,
                                            'female_total_price' => $row->female_total_price,
                        
                                            'sub_total' => $row->sub_total,
                                            'row_total' => $row->row_total,
                        
                                            'session_type' => $row->session_type,
                                            'session_type_display_text' => uiFast($row->session_type),
                        
                                            'role_type' => $row->role_type,
                                            'role_type_display_text' => uiFast($row->role_type),
                                        ];
                                    })->values()
                                ];
                            })
                            ->values();
                }
            
                return response()->json([
            
                    'message' => uiFast('Event details fetched'),
                    'status'  => '1',
            
                    'event_details' => [
            
                        'id' => $event->id,
                        'event_id' => $event->id,
            
                        'event_type' => $event->event_type,
                        'event_type_display_text' => uiFast($event->event_type),
            
                        'event_name' => $event->event_name,
                        'event_name_display_text' => transliterateTextKeepNumbers($event->event_name),
                        
                        
                        'event_city' => $event->event_city,
                        'event_city_display_text' => translateVenueLocation($event->event_city),
            
                        'event_from' => $event->event_from,
                        'event_to'   => $event->event_to,
            
                        'event_status' => $event->event_status,
                        'event_status_display_text' => uiFast($event->event_status),
            
                        'request_generated' => ($event->request_generated == "1"),
                    ],
            
                    'request_details' => $hireRequest ? [
            
                        'hire_role_request_id' => $hireRequest->id,
                        'grand_total' => (float) $hireRequest->grand_total,
            
                        /*
                            'request_status_value' => $hireRequest->request_status,
                            'request_status_display_text' => uiFast($hireRequest->request_status),
                        */
            
                    ] : null,
            
                    'roles' => $items,
            
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
            
                ], 200);
            }

