        public function proposallistings_2(Request $request)
            {
                $token = $request->header('Authorization');
            
                $user = $this->getuser($token);
            
                if (!$user)
                {
                    return response()->json([
            
                        'message' => uiFast('User not found'),
            
                        'status' => '0',
            
                        'data' => [],
            
                        'user_role' => "",
            
                        'logged_in_user' => []
            
                    ], 401);
                }
            
                $user_details = [
            
                    'name' => $user->name,
            
                    'email' => $user->email,
            
                    'mobile' => $user->mobile,
            
                    'business_name' => $user->business_name
            
                ];
            
                $useraccess = $this->checkeditaccess($token);
            
                $user_role = $useraccess['role'];
            
                $search = trim($request->search);
            
                $query = DB::table('client_proposals')
                    ->where('user_id', $user->id);
            
                if (!empty($search))
                {
                    $query->where(function($q) use ($search)
                    {
                        $q->where(
                                'couple_name',
                                'LIKE',
                                '%'.$search.'%'
                            )
                            ->orWhere(
                                'mobile_number',
                                'LIKE',
                                '%'.$search.'%'
                            )
                            ->orWhere(
                                'email_address',
                                'LIKE',
                                '%'.$search.'%'
                            )
                            ->orWhere(
                                'wedding_location',
                                'LIKE',
                                '%'.$search.'%'
                            )
                            ->orWhere(
                                'id',
                                $search
                            );
                    });
                }
            
                $proposals = $query
                    ->orderBy('id', 'DESC')
                    ->paginate(25);
            
                $proposal_list = [];
            
                foreach ($proposals as $proposal)
                {
                     
                    
                    
                    $proposal_list[] = [

                        'proposal_id' => $proposal->id,
                    
                        'couple_name' => $proposal->couple_name,
                    
                        'generated_date' => $proposal->created_on,
                    
                        'wedding_date' => $proposal->wedding_date,
                    
                        'wedding_duration_days' =>
                            $proposal->wedding_duration_days,
                            
                         'current_step' =>
                            (int)$proposal->current_step,
                    
                    ];
                }
            
                return response()->json([
            
                    'message' => uiFast(
                        'Proposal Listings'
                    ),
            
                    'status' => '1',
            
                    'page_title' => uiFast(
                        'Client Proposal'
                    ),
            
                    'default_screen' => [
            
                        'title' => uiFast(
                            'No Client Proposal Found'
                        ),
            
                        'description' => uiFast(
                            'We Haven\'t Found Any Proposal From Your Account. Craft Your First Beautiful Wedding Proposal'
                        )
            
                    ],
            
                    'search_text' => $search,
            
                    'proposal_count' =>
                        $proposals->total(),
            
                    'current_page' =>
                        $proposals->currentPage(),
            
                    'last_page' =>
                        $proposals->lastPage(),
            
                    'per_page' =>
                        $proposals->perPage(),
            
                    'proposal_list' =>
                        $proposal_list,
            
                    'user_role' =>
                        $user_role,
            
                    'logged_in_user' =>
                        $user_details
            
                ], 200);
            }
            
