        public function savecoupledetails_1(Request $request)
            {
                $token = $request->header('Authorization');
                $user  = $this->getuser($token);
            
                if (!$user) {
                    return response()->json([
                        'message' => uiFast('User not found'),
                        'status'  => '0',
                        'data'    => [],
                        'user_role' => "",
                        'logged_in_user' => [],
                    ], 401);
                }
            
                $user_details = [
                    'name' => $user->name,
                    'email' => $user->email,
                    'mobile' => $user->mobile,
                    'business_name' => $user->business_name
                ];
            
                $useraccess = $this->checkeditaccess($token);
                $user_role  = $useraccess['role'];
            
                $couple_name   = trim($request->couple_name);
                $mobile_number = trim($request->mobile_number);
                $email_address = trim($request->email_address);
            
                /*
                |--------------------------------------------------------------------------
                | Validation
                |--------------------------------------------------------------------------
                */
            
                if (empty($couple_name)) {
            
                    return response()->json([
                        'message' => uiFast('Please enter the couple name.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            
                if (empty($mobile_number)) {
            
                    return response()->json([
                        'message' => uiFast('Please enter the mobile number.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            
                if (!preg_match('/^[0-9]{10}$/', $mobile_number)) {
            
                    return response()->json([
                        'message' => uiFast('Mobile number must contain exactly 10 digits.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            
                if (!empty($email_address) && !filter_var($email_address, FILTER_VALIDATE_EMAIL)) {
            
                    return response()->json([
                        'message' => uiFast('Please enter a valid email address.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            
                $currentTime = \Carbon\Carbon::now('Asia/Kolkata')->format('Y-m-d H:i:s');
            
                /*
                |--------------------------------------------------------------------------
                | EDIT MODE
                |--------------------------------------------------------------------------
                */
            
                if ($request->has('proposal_id') && trim($request->proposal_id) != '') {
            
                    $proposal_id = trim($request->proposal_id);
            
                    $proposal = DB::table('client_proposals')
                        ->where('id', $proposal_id)
                        ->first();
            
                    if (!$proposal) {
            
                        return response()->json([
                            'message' => uiFast('Invalid proposal selected.'),
                            'status'  => '0',
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 200);
                    }
            
                    if ($proposal->user_id != $user->id) {
            
                        return response()->json([
                            'message' => uiFast('You do not have permission to access this proposal.'),
                            'status'  => '0',
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 200);
                    }
            
                    DB::table('client_proposals')
                        ->where('id', $proposal_id)
                        ->update([
                            'couple_name'   => $couple_name,
                            'mobile_number' => $mobile_number,
                            'email_address' => $email_address,
                            'current_step'  => 1,
                            'updated_at'    => $currentTime
                        ]);
            
                    $action = 'updated';
                }
            
                /*
                |--------------------------------------------------------------------------
                | CREATE MODE
                |--------------------------------------------------------------------------
                */
                else {
            
                    $proposal_id = DB::table('client_proposals')->insertGetId([
            
                        'user_id' => $user->id,
            
                        'couple_name'   => $couple_name,
                        'mobile_number' => $mobile_number,
                        'email_address' => $email_address,
            
                        'current_step'    => 1,
                        'proposal_status' => 'Draft',
            
                        'created_on' => \Carbon\Carbon::now('Asia/Kolkata')
                            ->format('d/m/Y h:i A'),
            
                        'created_at' => $currentTime,
                        'updated_at' => $currentTime
            
                    ]);
            
                    $action = 'created';
                }
            
                return response()->json([
            
                    'message' => uiFast('Couple details saved successfully.'),
                    'status'  => '1',
            
                    'action' => $action,
            
                    'proposal_id' => $proposal_id,
            
                    'step_number' => 1,
                    'total_steps' => 4,
                    'step_display_text' => uiFast('1/4'),
            
                    'page_title' => uiFast('The Couple Details'),
            
                    'page_description' => uiFast(
                        'Let\'s begin with their beautiful story'
                    ),
            
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
            
                ], 200);
            }
            
