                $user_role  = $useraccess['role'];
            
                $proposal_id           = trim($request->proposal_id);
                $wedding_date          = trim($request->wedding_date);
                $wedding_duration_days = trim($request->wedding_duration_days);
                $wedding_location      = trim($request->wedding_location);
                $wedding_style         = trim($request->wedding_style);
                $custom_wedding_style  = trim($request->custom_wedding_style);
            
                /*
                |--------------------------------------------------------------------------
                | Proposal Validation
                |--------------------------------------------------------------------------
                */
            
                if (empty($proposal_id)) {
            
                    return response()->json([
                        'message' => uiFast('Proposal ID is required.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            
                $proposal = DB::table('client_proposals')
                    ->where('id', $proposal_id)
                    ->first();
            
                if (!$proposal) {
            
                    return response()->json([
                        'message' => uiFast('Invalid proposal selected.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            
                if ($proposal->user_id != $user->id) {
            
                    return response()->json([
                        'message' => uiFast('You do not have permission to access this proposal.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            
                /*
                |--------------------------------------------------------------------------
                | Wedding Date Validation
                |--------------------------------------------------------------------------
                */
            
                if (empty($wedding_date)) {
            
                    return response()->json([
                        'message' => uiFast('Please select a wedding date.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            
                if (!preg_match('/^\d{2}\/\d{2}\/\d{4}$/', $wedding_date)) {
            
                    return response()->json([
                        'message' => uiFast('Wedding date must be in DD/MM/YYYY format.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            
                /*
                |--------------------------------------------------------------------------
                | Wedding Duration Validation
                |--------------------------------------------------------------------------
                */
            
                if (empty($wedding_duration_days)) {
            
                    return response()->json([
                        'message' => uiFast('Please enter wedding duration.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            
                if (!ctype_digit($wedding_duration_days)) {
            
                    return response()->json([
                        'message' => uiFast('Wedding duration must be numbers only.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            
                /*
                |--------------------------------------------------------------------------
                | Wedding Location Validation
                |--------------------------------------------------------------------------
                */
            
                if (empty($wedding_location)) {
            
                    return response()->json([
                        'message' => uiFast('Please enter wedding location.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            
                /*
                |--------------------------------------------------------------------------
                | Wedding Style Validation
                |--------------------------------------------------------------------------
                */
            
                $allowedStyles = [
            
                    'traditional_indian',
                    'bohemian',
                    'royal_rajasthani',
                    'beach_destination',
                    'minimalist_modern',
                    'garden_romance',
                    'vintage_classic',
                    'south_indian_temple',
                    'goa_beach',
                    'contemporary_luxury'
            
                ];
            
                if (empty($wedding_style) && empty($custom_wedding_style)) {
            
                    return response()->json([
                        'message' => uiFast('Please select a wedding style or describe your own style.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            
                if (!empty($wedding_style) && !empty($custom_wedding_style)) {
            
                    return response()->json([
                        'message' => uiFast('Please choose either a wedding style or your own style, not both.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            
                if (!empty($wedding_style)) {
            
                    if (strpos($wedding_style, ',') !== false) {
            
                        return response()->json([
                            'message' => uiFast('Please select only one wedding style.'),
                            'status'  => '0',
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 200);
                    }
            
                    if (!in_array($wedding_style, $allowedStyles)) {
            
                        return response()->json([
                            'message' => uiFast('Invalid wedding style selected.'),
                            'status'  => '0',
                            'user_role' => $user_role,
                            'logged_in_user' => $user_details,
                        ], 200);
                    }
                }
            
                /*
                |--------------------------------------------------------------------------
                | Save
                |--------------------------------------------------------------------------
                */
            
                DB::table('client_proposals')
                    ->where('id', $proposal_id)
                    ->update([
            
                        'wedding_date' => $wedding_date,
                        'wedding_duration_days' => $wedding_duration_days,
                        'wedding_location' => $wedding_location,
                        'wedding_style' => $wedding_style,
                        'custom_wedding_style' => $custom_wedding_style,
            
                        'current_step' => 2,
            
                        'updated_at' => \Carbon\Carbon::now('Asia/Kolkata')
                            ->format('Y-m-d H:i:s')
                    ]);
            
                return response()->json([
            
                    'message' => uiFast('Celebration details saved successfully.'),
                    'status'  => '1',
            
                    'proposal_id' => $proposal_id,
            
                    'step_number' => 2,
                    'total_steps' => 4,
                    'step_display_text' => uiFast('2/4'),
            
                    'page_title' => uiFast('The Celebration'),
            
                    'page_description' => uiFast(
                        'The canvas for their love story'
                    ),
            
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
            
                ], 200);
            }
            
             
            
        public function scopeofworklist(Request $request)
            {
                $token = $request->header('Authorization');
                $user  = $this->getuser($token);
            
                if (!$user) {
                    return response()->json([
                        'message' => uiFast('User not found'),
                        'status' => '0',
                        'data' => [],
                        'user_role' => '',
                        'logged_in_user' => [],
                    ], 401);
                }
            
                $user_details = [
                    'name' => $user->name,
                    'email' => $user->email,
                    'mobile' => $user->mobile,
                    'business_name' => $user->business_name
                ];
            
                $useraccess = $this->checkeditaccess($token);
                $user_role = $useraccess['role'];
            
                $scope_values = [
            
                    'venue',
                    'catering',
                    'decoration',
                    'photo_videography',
                    'dj_entertainment',
                    'invitations',
                    'attire',
                    'others'
            
                ];
            
                $scope_of_work = [];
            
                foreach ($scope_values as $scope) {
            
                    $scope_of_work[] = [
            
                        'scope_value' => $scope,
            
                        'scope_display_text' =>
                            __('dashboard.scope_of_work.'.$scope)
            
                    ];
                }
            
                return response()->json([
            
                    'message' => uiFast('Scope Of Work'),
                    'status' => '1',
            
                    'scope_of_work' => $scope_of_work,
            
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
            
                ], 200);
            }
            
            
