        public function savescopeofwork_1(Request $request)
            {
                $token = $request->header('Authorization');
                $user  = $this->getuser($token);
            
                if (!$user) {
                    return response()->json([
                        'message' => uiFast('User not found'),
                        'status'  => '0',
                        'data'    => [],
                        'user_role' => "",
                        'logged_in_user' => [],
                    ], 401);
                }

                $user_details = [
                    'name' => $user->name,
                    'email' => $user->email,
                    'mobile' => $user->mobile,
                    'business_name' => $user->business_name
                ];
            
                $useraccess = $this->checkeditaccess($token);
                $user_role  = $useraccess['role'];
            
                /*
                |--------------------------------------------------------------------------
                | Proposal Validation
                |--------------------------------------------------------------------------
                */

                $proposal_id = trim($request->proposal_id);
            
                if (empty($proposal_id)) {
            
                    return response()->json([
                        'message' => uiFast('Proposal ID is required.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            
                $proposal = DB::table('client_proposals')
                    ->where('id', $proposal_id)
                    ->first();
            
                if (!$proposal) {
            
                    return response()->json([
                        'message' => uiFast('Invalid proposal selected.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }

            if ($proposal->user_id != $user->id) {
        
                return response()->json([
                    'message' => uiFast('You do not have permission to access this proposal.'),
                    'status'  => '0',
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                ], 200);
            }
        
            /*
            |--------------------------------------------------------------------------
            | Scope Data Validation
            |--------------------------------------------------------------------------
            */
        
            if (empty($request->scope_data)) {
        
                return response()->json([
                    'message' => uiFast('Scope data is required.'),
                    'status'  => '0',
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                ], 200);
            }
        
            $scope_data = json_decode($request->scope_data, true);
        
            if (json_last_error() !== JSON_ERROR_NONE) {
        
                return response()->json([
                    'message' => uiFast('Invalid scope data format.'),
                    'status'  => '0',
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                ], 200);
            }

            if (!is_array($scope_data) || count($scope_data) == 0) {
        
                return response()->json([
                    'message' => uiFast('Please add at least one event.'),
                    'status'  => '0',
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                ], 200);
            }
        
            /*
            |--------------------------------------------------------------------------
            | Event Level Validation
            |--------------------------------------------------------------------------
            */
        
            foreach ($scope_data as $eventIndex => $event) {
        
                if (empty(trim($event['event_name'] ?? ''))) {
        
                    return response()->json([
                        'message' => uiFast(
                            'Event name is required.'
                        ),
                        'status' => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
        
                if (empty(trim($event['event_date'] ?? ''))) {
        
                    return response()->json([
                        'message' => uiFast(
                            'Event date is required.'
                        ),
                        'status' => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
        
                $date = DateTime::createFromFormat(
                    'd/m/Y',
                    trim($event['event_date'])
                );
                
                if (
                    !$date ||
                    $date->format('d/m/Y') != trim($event['event_date'])
                )
                {
                    return response()->json([
                        'message' => uiFast(
                            'Event date must be a valid date in DD/MM/YYYY format.'
                        ),
                        'status' => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
                if (empty(trim($event['event_time'] ?? ''))) {
        
                    return response()->json([
                        'message' => uiFast(
                            'Event time is required.'
                        ),
                        'status' => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
        
                if (
                    !preg_match(
                        '/^(0?[1-9]|1[0-2]):[0-5][0-9]\s?(AM|PM)$/i',
                        trim($event['event_time'])
                    )
                ) {
        
                    return response()->json([
                        'message' => uiFast(
                            'Event time must be in HH:MM AM/PM format.'
                        ),
                        'status' => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
        
                if (
                    !isset($event['scopes']) ||
                    !is_array($event['scopes']) ||
                    count($event['scopes']) == 0
                ) {
        
                    return response()->json([
                        'message' => uiFast(
                            'Please select at least one scope of work.'
                        ),
                        'status' => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            }
        
            /*
            |--------------------------------------------------------------------------
            | Begin Transaction
            |--------------------------------------------------------------------------
            */
        
            DB::beginTransaction();
        
            try {
        
                /*
                |--------------------------------------------------------------------------
                | Delete Existing Scope Images
                |--------------------------------------------------------------------------
                */
        
                DB::table('proposal_scope_images')
                    ->whereIn(
                        'proposal_scope_item_id',
                        function ($query) use ($proposal_id) {
        
                            $query->select('psi.id')
                                ->from('proposal_scope_items as psi')
                                ->join(
                                    'proposal_events as pe',
                                    'pe.id',
                                    '=',
                                    'psi.proposal_event_id'
                                )
                                ->where(
                                    'pe.proposal_id',
                                    $proposal_id
                                );
                        }
                    )
                    ->delete();
        
                /*
                |--------------------------------------------------------------------------
                | Delete Existing Scope Items
                |--------------------------------------------------------------------------
                */
        
                DB::table('proposal_scope_items')
                    ->whereIn(
                        'proposal_event_id',
                        function ($query) use ($proposal_id) {
        
                            $query->select('id')
                                ->from('proposal_events')
                                ->where(
                                    'proposal_id',
                                    $proposal_id
                                );
                        }
                    )
                    ->delete();
        
                /*
                |--------------------------------------------------------------------------
                | Delete Existing Events
                |--------------------------------------------------------------------------
                */
        
                DB::table('proposal_events')
                    ->where('proposal_id', $proposal_id)
                    ->delete();
        
                /*
                |--------------------------------------------------------------------------
                | Ready To Save Fresh Data
                |--------------------------------------------------------------------------
                */
        
                $now = Carbon::now('Asia/Kolkata')
                    ->format('Y-m-d H:i:s');
        
                $savedEvents = [];
                
                /*
                    |--------------------------------------------------------------------------
                    | Save Events & Scopes
                    |--------------------------------------------------------------------------
                    */
                    
                    foreach ($scope_data as $event)
                    {
                        $event_id = DB::table('proposal_events')
                            ->insertGetId([
                    
                                'proposal_id' => $proposal_id,
                    
                                'day_number' => $event['day_number'] ?? 1,
                    
                                'event_name' => trim($event['event_name']),
                    
                                'event_date' => trim($event['event_date']),
                    
                                'event_time' => trim($event['event_time']),
                    
                                'created_at' => $now,
                                'updated_at' => $now
                    
                            ]);
                    
                        $savedEvents[] = $event_id;
                    
                        if (
                            isset($event['scopes']) &&
                            is_array($event['scopes'])
                        )
                            {
                            foreach ($event['scopes'] as $scope)
                            {
                                $scope_type = strtolower(
                                    trim($scope['scope_type'] ?? '')
                                );
                    
                                /*
                                |--------------------------------------------------------------------------
                                | Scope Validations
                                |--------------------------------------------------------------------------
                                */
                    
                                if (empty($scope_type))
                                {
                                    DB::rollBack();
                    
                                    return response()->json([
                                        'message' => uiFast(
                                            'Scope type is required.'
                                        ),
                                        'status' => '0',
                                        'user_role' => $user_role,
                                        'logged_in_user' => $user_details,
                                    ], 200);
                                }
                    
                                /*
                                |--------------------------------------------------------------------------
                                | Venue Validation
                                |--------------------------------------------------------------------------
                                */
                    
                                if ($scope_type == 'venue')
                                {
                                    if (empty($scope['venue_type']))
                                    {
                                        DB::rollBack();
                    
                                        return response()->json([
                                            'message' => uiFast(
                                                'Venue type is required.'
                                            ),
                                            'status' => '0',
                                            'user_role' => $user_role,
                                            'logged_in_user' => $user_details,
                                        ], 200);
                                    }
                    
                                    if (
                                        !empty($scope['seating_capacity']) &&
                                        !ctype_digit(
                                            (string) $scope['seating_capacity']
                                        )
                                    )
                                    {
                                        DB::rollBack();
                    
                                        return response()->json([
                                            'message' => uiFast(
                                                'Seating capacity must be numeric.'
                                            ),
                                            'status' => '0',
                                            'user_role' => $user_role,
                                            'logged_in_user' => $user_details,
                                        ], 200);
                                    }
                    
                                    if (
                                        !empty($scope['room_needed']) &&
                                        !ctype_digit(
                                            (string) $scope['room_needed']
                                        )
                                    )
                                    {
                                        DB::rollBack();
                    
                                        return response()->json([
                                            'message' => uiFast(
                                                'Room needed must be numeric.'
                                            ),
                                            'status' => '0',
                                            'user_role' => $user_role,
                                            'logged_in_user' => $user_details,
                                        ], 200);
                                    }
                                }
                    
                                /*
                                |--------------------------------------------------------------------------
                                | Catering Validation
                                |--------------------------------------------------------------------------
                                */
                    
                                if (
                                    $scope_type == 'catering' &&
                                    isset($scope['meal_types'])
                                )
                                {
                                    foreach (
                                        $scope['meal_types']
                                        as $meal
                                    )
                                    {
                                        if (
                                            !empty($meal['meal_cost']) &&
                                            !is_numeric(
                                                $meal['meal_cost']
                                            )
                                        )
                                        {
                                            DB::rollBack();
                    
                                            return response()->json([
                                                'message' => uiFast(
                                                    'Meal cost must be numeric.'
                                                ),
                                                'status' => '0',
                                                'user_role' => $user_role,
                                                'logged_in_user' => $user_details,
                                            ], 200);
                                        }
                    
                                        if (
                                            !empty($meal['head_count']) &&
                                            !ctype_digit(
                                                (string) $meal['head_count']
                                            )
                                        )
                                        {
                                            DB::rollBack();
                    
                                            return response()->json([
                                                'message' => uiFast(
                                                    'Head count must be numeric.'
                                                ),
                                                'status' => '0',
                                                'user_role' => $user_role,
                                                'logged_in_user' => $user_details,
                                            ], 200);
                                        }
                                    }
                                }
                    
                                /*
                                |--------------------------------------------------------------------------
                                | Save Scope Item
                                |--------------------------------------------------------------------------
                                */
                    
                                $scope_item_id =
                                    DB::table('proposal_scope_items')
                                        ->insertGetId([
                    
                                            'proposal_event_id' => $event_id,
                    
                                            'scope_type' => $scope_type,
                    
                                            'data_json' => json_encode(
                                                $scope,
                                                JSON_UNESCAPED_UNICODE
                                            ),
                    
                                            'created_at' => $now,
                                            'updated_at' => $now
                    
                                        ]);
                    
                                /*
                                |--------------------------------------------------------------------------
                                | Upload Scope Images
                                |--------------------------------------------------------------------------
                                */
                    
                                $scope_index =
                                    $scope['scope_index'] ?? null;
                    
                                if (!empty($scope_index))
                                {
                                    $imageField =
                                        'scope_'.$scope_index.'_images';
                    
                                    if ($request->hasFile($imageField))
                                    {
                                        $files = $request->file($imageField);
                    
                                        if (!is_array($files))
                                        {
                                            $files = [$files];
                                        }
                                        
                                        if (count($files) > 8)
                                        {
                                            DB::rollBack();
                    
                                            return response()->json([
                                                'message' => uiFast(
                                                    'Maximum 8 images allowed per scope.'
                                                ),
                                                'status' => '0',
                                                'user_role' => $user_role,
                                                'logged_in_user' => $user_details,
                                            ], 200);
                                        }
                    
                                        foreach ($files as $file)
                                        {
                                            if (!$file)
                                            {
                                                continue;
                                            }
                    
                                            $extension =
                                                strtolower(
                                                    $file->getClientOriginalExtension()
                                                );
                    
                                            $allowed =
                                            [
                                                'jpg',
                                                'jpeg',
                                                'png',
                                                'webp'
                                            ];
                    
                                            if (
                                                !in_array(
                                                    $extension,
                                                    $allowed
                                                )
                                            )
                                            {
                                                continue;
                                            }
                    
                                            $filename =
                                                time().
                                                uniqid().
                                                '.'.
                                                $extension;
                    
                                            $relativePath =
                                                'proposalscopeimages/'.
                                                strtolower($filename);
                                            $uploadPath = '/home/gjymj6oxru2v/planawedding/storage/app/public/proposalscopeimages/';

                                            if (!File::exists($uploadPath))
                                            {
                                                File::makeDirectory(
                                                    $uploadPath,
                                                    0755,
                                                    true
                                                );
                                            }
                                            $file->move(
                                                '/home/gjymj6oxru2v/planawedding/storage/app/public/proposalscopeimages/',
                                                strtolower($filename)
                                            );
                    
                                            DB::table(
                                                'proposal_scope_images'
                                            )
                                            ->insert([
                    
                                                'proposal_scope_item_id' =>
                                                    $scope_item_id,
                    
                                                'image_path' =>
                                                    $relativePath,
                    
                                                'created_at' =>
                                                    $now
                    
                                            ]);
                                        }
                                    }
                                }
                            }
                        }
                        
                        
                    }
                    
                    
                        /*
                |--------------------------------------------------------------------------
                | Update Proposal Step
                |--------------------------------------------------------------------------
                */
        
                DB::table('client_proposals')
                ->where('id', $proposal_id)
                ->update([
            
                    'current_step' => 3,
            
                    'proposal_status' => 'Draft',
            
                    'updated_at' => Carbon::now('Asia/Kolkata')
                        ->format('Y-m-d H:i:s')
            
                ]);
        
                /*
                |--------------------------------------------------------------------------
                | Commit Transaction
                |--------------------------------------------------------------------------
                */
        
                DB::commit();
        
                return response()->json([
        
                    'message' => uiFast(
                        'Scope of work saved successfully.'
                    ),
        
                    'status' => '1',
        
                    'proposal_id' => $proposal_id,
        
                    'step_number' => 3,
        
                    'total_steps' => 4,
        
                    'step_display_text' => uiFast('3/4'),
        
                    'page_title' => uiFast(
                        'Scope Of Work'
                    ),
        
                    'page_description' => uiFast(
                        'Services tailored for their dream day'
                    ),
        
                    'saved_events_count' =>
                        count($savedEvents),
        
                    'user_role' => $user_role,
        
                    'logged_in_user' => $user_details,
        
                ], 200);
        
            }
            catch (\Exception $e)
            {
                DB::rollBack();
        
                Log::error(
                    'Save Scope Of Work Error',
                    [
                        'proposal_id' => $proposal_id ?? null,
                        'user_id' => $user->id ?? null,
                        'error' => $e->getMessage(),
                        'line' => $e->getLine(),
                        'file' => $e->getFile()
                    ]
                );
        
                return response()->json([
        
                    'message' => uiFast(
                        'Unable to save scope of work. Please try again.'
                    ),
        
                    'status' => '0',
        
                    'user_role' => $user_role,
        
                    'logged_in_user' => $user_details,
        
                ], 500);
            }
        }
        
         public function savescopeofwork(Request $request)
            {
                $token = $request->header('Authorization');
                $user  = $this->getuser($token);
            
                if (!$user) {
                    return response()->json([
                        'message' => uiFast('User not found'),
                        'status'  => '0',
                        'data'    => [],
                        'user_role' => "",
                        'logged_in_user' => [],
                    ], 401);
                }

                $user_details = [
                    'name' => $user->name,
                    'email' => $user->email,
                    'mobile' => $user->mobile,
                    'business_name' => $user->business_name
                ];
            
                $useraccess = $this->checkeditaccess($token);
                $user_role  = $useraccess['role'];
            
                /*
                |--------------------------------------------------------------------------
                | Proposal Validation
                |--------------------------------------------------------------------------
                */

                $proposal_id = trim($request->proposal_id);
            
                if (empty($proposal_id)) {
            
                    return response()->json([
                        'message' => uiFast('Proposal ID is required.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            
                $proposal = DB::table('client_proposals')
                    ->where('id', $proposal_id)
                    ->first();
            
                if (!$proposal) {
            
                    return response()->json([
                        'message' => uiFast('Invalid proposal selected.'),
                        'status'  => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }

            if ($proposal->user_id != $user->id) {
        
                return response()->json([
                    'message' => uiFast('You do not have permission to access this proposal.'),
                    'status'  => '0',
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                ], 200);
            }
        
            /*
            |--------------------------------------------------------------------------
            | Scope Data Validation
            |--------------------------------------------------------------------------
            */
        
            if (empty($request->scope_data)) {
        
                return response()->json([
                    'message' => uiFast('Scope data is required.'),
                    'status'  => '0',
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                ], 200);
            }
        
            $scope_data = json_decode($request->scope_data, true);
        
            if (json_last_error() !== JSON_ERROR_NONE) {
        
                return response()->json([
                    'message' => uiFast('Invalid scope data format.'),
                    'status'  => '0',
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                ], 200);
            }

            if (!is_array($scope_data) || count($scope_data) == 0) {
        
                return response()->json([
                    'message' => uiFast('Please add at least one event.'),
                    'status'  => '0',
                    'user_role' => $user_role,
                    'logged_in_user' => $user_details,
                ], 200);
            }
        
            /*
            |--------------------------------------------------------------------------
            | Event Level Validation
            |--------------------------------------------------------------------------
            */
        
            foreach ($scope_data as $eventIndex => $event) {
        
                if (empty(trim($event['event_name'] ?? ''))) {
        
                    return response()->json([
                        'message' => uiFast(
                            'Event name is required.'
                        ),
                        'status' => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
        
                if (empty(trim($event['event_date'] ?? ''))) {
        
                    return response()->json([
                        'message' => uiFast(
                            'Event date is required.'
                        ),
                        'status' => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
        
                $date = DateTime::createFromFormat(
                    'd/m/Y',
                    trim($event['event_date'])
                );
                
                if (
                    !$date ||
                    $date->format('d/m/Y') != trim($event['event_date'])
                )
                {
                    return response()->json([
                        'message' => uiFast(
                            'Event date must be a valid date in DD/MM/YYYY format.'
                        ),
                        'status' => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
                if (empty(trim($event['event_time'] ?? ''))) {
        
                    return response()->json([
                        'message' => uiFast(
                            'Event time is required.'
                        ),
                        'status' => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
        
                if (
                    !preg_match(
                        '/^(0?[1-9]|1[0-2]):[0-5][0-9]\s?(AM|PM)$/i',
                        trim($event['event_time'])
                    )
                ) {
        
                    return response()->json([
                        'message' => uiFast(
                            'Event time must be in HH:MM AM/PM format.'
                        ),
                        'status' => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
        
                if (
                    !isset($event['scopes']) ||
                    !is_array($event['scopes']) ||
                    count($event['scopes']) == 0
                ) {
        
                    return response()->json([
                        'message' => uiFast(
                            'Please select at least one scope of work.'
                        ),
                        'status' => '0',
                        'user_role' => $user_role,
                        'logged_in_user' => $user_details,
                    ], 200);
                }
            }
        
            /*
            |--------------------------------------------------------------------------
            | Begin Transaction
            |--------------------------------------------------------------------------
            */
        
            DB::beginTransaction();
        
            try {
        
                /*
                |--------------------------------------------------------------------------
                | Delete Existing Scope Images
                |--------------------------------------------------------------------------
                */
        
                DB::table('proposal_scope_images')
                    ->whereIn(
                        'proposal_scope_item_id',
                        function ($query) use ($proposal_id) {
        
                            $query->select('psi.id')
                                ->from('proposal_scope_items as psi')
                                ->join(
                                    'proposal_events as pe',
                                    'pe.id',
                                    '=',
                                    'psi.proposal_event_id'
                                )
                                ->where(
                                    'pe.proposal_id',
                                    $proposal_id
                                );
                        }
                    )
                    ->delete();
        
                /*
                |--------------------------------------------------------------------------
                | Delete Existing Scope Items
                |--------------------------------------------------------------------------
                */
        
                DB::table('proposal_scope_items')
                    ->whereIn(
                        'proposal_event_id',
                        function ($query) use ($proposal_id) {
        
                            $query->select('id')
                                ->from('proposal_events')
                                ->where(
                                    'proposal_id',
                                    $proposal_id
                                );
                        }
                    )
                    ->delete();
        
                /*
                |--------------------------------------------------------------------------
                | Delete Existing Events
                |--------------------------------------------------------------------------
                */
        
                DB::table('proposal_events')
                    ->where('proposal_id', $proposal_id)
                    ->delete();
        
                /*
                |--------------------------------------------------------------------------
                | Ready To Save Fresh Data
                |--------------------------------------------------------------------------
                */
        
                $now = Carbon::now('Asia/Kolkata')
                    ->format('Y-m-d H:i:s');
        
                $savedEvents = [];
                
                /*
                    |--------------------------------------------------------------------------
                    | Save Events & Scopes
                    |--------------------------------------------------------------------------
                    */
                    
                    foreach ($scope_data as $event)
                    {
                        $event_id = DB::table('proposal_events')
                            ->insertGetId([
                    
                                'proposal_id' => $proposal_id,
                    
                                'day_number' => $event['day_number'] ?? 1,
                    
                                'event_name' => trim($event['event_name']),
                    
                                'event_date' => trim($event['event_date']),
                    
                                'event_time' => trim($event['event_time']),
                    
                                'created_at' => $now,
                                'updated_at' => $now
                    
                            ]);
                    
                        $savedEvents[] = $event_id;
                    
                        if (
                            isset($event['scopes']) &&
                            is_array($event['scopes'])
                        )
                            {
                            foreach ($event['scopes'] as $scope)
                            {
                                $scope_type = strtolower(
                                    trim($scope['scope_type'] ?? '')
                                );
                    
                                /*
                                |--------------------------------------------------------------------------
                                | Scope Validations
                                |--------------------------------------------------------------------------
                                */
                    
                                if (empty($scope_type))
                                {
                                    DB::rollBack();
                    
                                    return response()->json([
                                        'message' => uiFast(
                                            'Scope type is required.'
                                        ),
                                        'status' => '0',
                                        'user_role' => $user_role,
                                        'logged_in_user' => $user_details,
                                    ], 200);
                                }
                    
                                /*
                                |--------------------------------------------------------------------------
                                | Venue Validation
                                |--------------------------------------------------------------------------
                                */
                    
                                if ($scope_type == 'venue')
                                {
                                    if (empty($scope['venue_type']))
                                    {
                                        DB::rollBack();
                    
                                        return response()->json([
                                            'message' => uiFast(
                                                'Venue type is required.'
                                            ),
                                            'status' => '0',
                                            'user_role' => $user_role,
                                            'logged_in_user' => $user_details,
                                        ], 200);
                                    }
                    
                                    if (
                                        !empty($scope['seating_capacity']) &&
                                        !ctype_digit(
                                            (string) $scope['seating_capacity']
                                        )
                                    )
                                    {
                                        DB::rollBack();
                    
                                        return response()->json([
                                            'message' => uiFast(
                                                'Seating capacity must be numeric.'
                                            ),
                                            'status' => '0',
                                            'user_role' => $user_role,
                                            'logged_in_user' => $user_details,
                                        ], 200);
                                    }
                    
                                    if (
                                        !empty($scope['room_needed']) &&
                                        !ctype_digit(
                                            (string) $scope['room_needed']
                                        )
                                    )
                                    {
                                        DB::rollBack();
                    
                                        return response()->json([
                                            'message' => uiFast(
                                                'Room needed must be numeric.'
                                            ),
                                            'status' => '0',
                                            'user_role' => $user_role,
                                            'logged_in_user' => $user_details,
                                        ], 200);
                                    }
                                }
                    
                                /*
                                |--------------------------------------------------------------------------
                                | Catering Validation
                                |--------------------------------------------------------------------------
                                */
                    
                                if (
                                    $scope_type == 'catering' &&
                                    isset($scope['meal_types'])
                                )
                                {
                                    foreach (
                                        $scope['meal_types']
                                        as $meal
                                    )
                                    {
                                        if (
                                            !empty($meal['meal_cost']) &&
                                            !is_numeric(
                                                $meal['meal_cost']
                                            )
                                        )
                                        {
                                            DB::rollBack();
                    
                                            return response()->json([
                                                'message' => uiFast(
                                                    'Meal cost must be numeric.'
                                                ),
                                                'status' => '0',
                                                'user_role' => $user_role,
                                                'logged_in_user' => $user_details,
                                            ], 200);
                                        }
                    
                                        if (
                                            !empty($meal['head_count']) &&
                                            !ctype_digit(
                                                (string) $meal['head_count']
                                            )
                                        )
                                        {
                                            DB::rollBack();
                    
                                            return response()->json([
                                                'message' => uiFast(
                                                    'Head count must be numeric.'
                                                ),
                                                'status' => '0',
                                                'user_role' => $user_role,
                                                'logged_in_user' => $user_details,
                                            ], 200);
                                        }
                                    }
                                }
                    
                                /*
                                |--------------------------------------------------------------------------
                                | Save Scope Item
                                |--------------------------------------------------------------------------
                                */
                    
                                $scope_item_id =
                                    DB::table('proposal_scope_items')
                                        ->insertGetId([
                    
                                            'proposal_event_id' => $event_id,
                    
                                            'scope_type' => $scope_type,
                    
                                            'data_json' => json_encode(
                                                $scope,
                                                JSON_UNESCAPED_UNICODE
                                            ),
                    
                                            'created_at' => $now,
                                            'updated_at' => $now
                    
                                        ]);
                    
                                /*
                                |--------------------------------------------------------------------------
                                | Upload Scope Images
                                |--------------------------------------------------------------------------
                                */
                    
                                $scope_index =
                                    $scope['scope_index'] ?? null;
                    
                                if (!empty($scope_index))
                                {
                                    $imageField =
                                        'scope_'.$scope_index.'_images';
                    
                                    if ($request->hasFile($imageField))
                                    {
                                        $files = $request->file($imageField);
                    
                                        if (!is_array($files))
                                        {
                                            $files = [$files];
                                        }
                                        
                                        if (count($files) > 8)
                                        {
                                            DB::rollBack();
                    
                                            return response()->json([
                                                'message' => uiFast(
                                                    'Maximum 8 images allowed per scope.'
                                                ),
                                                'status' => '0',
                                                'user_role' => $user_role,
                                                'logged_in_user' => $user_details,
                                            ], 200);
                                        }
                    
                                        foreach ($files as $file)
                                        {
                                            if (!$file)
                                            {
                                                continue;
                                            }
                                            
                                           
                    
                                            $extension =
                                                strtolower(
                                                    $file->getClientOriginalExtension()
                                                );
                    
                                            $allowed =
                                                [
                                                    'jpg',
                                                    'jpeg',
                                                    'png',
                                                    'webp',
                                                    'svg'
                                                ];
                                                
                                                if (!in_array($extension, $allowed))
                                                {
                                                    continue;
                                                }
                                                
                                                $filename =
                                                    time().
                                                    uniqid().
                                                    '.'.
                                                    $extension;
                                                
                                                $filename = strtolower($filename);
                                                
                                                $relativePath =
                                                    'proposalscopeimages/'.
                                                    $filename;
                                                
                                                $uploadPath =
                                                    '/home/gjymj6oxru2v/planawedding/storage/app/public/proposalscopeimages/';
                                                
                                                if (!File::exists($uploadPath))
                                                {
                                                    File::makeDirectory(
                                                        $uploadPath,
                                                        0755,
                                                        true
                                                    );
                                                }
                                                
                                                /*
                                                |--------------------------------------------------------------------------
                                                | SVG - Keep Original
                                                |--------------------------------------------------------------------------
                                                */
                                                
                                                if ($extension == 'svg')
                                                {
                                                    $file->move(
                                                        $uploadPath,
                                                        $filename
                                                    );
                                                }
                                                
                                                /*
                                                |--------------------------------------------------------------------------
                                                | JPG / JPEG / WEBP
                                                |--------------------------------------------------------------------------
                                                */
                                                
                                                else if (
                                                    in_array(
                                                        $extension,
                                                        ['jpg','jpeg','webp']
                                                    )
                                                )
                                                {
                                                    /*
                                                        $image = Image::make($file);
                                                    
                                                        $image->save(
                                                            $uploadPath.$filename,
                                                            90
                                                        );
                                                    */
                                                    
                                                    $image = Image::make($file)
                                                        ->orientate();
                                                    
                                                    $image->save(
                                                        $uploadPath.$filename,
                                                        90
                                                    );
                                                }
                                                
                                                /*
                                                |--------------------------------------------------------------------------
                                                | PNG
                                                |--------------------------------------------------------------------------
                                                */
                                                
                                                else if ($extension == 'png')
                                                {
                                                    $image = Image::make($file);
                                                
                                                    $image->save(
                                                        $uploadPath.$filename
                                                    );
                                                }
                    
                                            DB::table(
                                                'proposal_scope_images'
                                            )
                                            ->insert([
                    
                                                'proposal_scope_item_id' =>
                                                    $scope_item_id,
                    
                                                'image_path' =>
                                                    $relativePath,
                    
                                                'created_at' =>
                                                    $now
                    
                                            ]);
                                        }
                                    }
                                }
                            }
                        }
                        
                        
                    }
                    
                    
                        /*
                |--------------------------------------------------------------------------
                | Update Proposal Step
                |--------------------------------------------------------------------------
                */
        
                DB::table('client_proposals')
                ->where('id', $proposal_id)
                ->update([
            
                    'current_step' => 3,
            
                    'proposal_status' => 'Draft',
            
                    'updated_at' => Carbon::now('Asia/Kolkata')
                        ->format('Y-m-d H:i:s')
            
                ]);
        
                /*
                |--------------------------------------------------------------------------
                | Commit Transaction
                |--------------------------------------------------------------------------
                */
        
                DB::commit();
        
                return response()->json([
        
                    'message' => uiFast(
                        'Scope of work saved successfully.'
                    ),
        
                    'status' => '1',
        
                    'proposal_id' => $proposal_id,
        
                    'step_number' => 3,
        
                    'total_steps' => 4,
        
                    'step_display_text' => uiFast('3/4'),
        
                    'page_title' => uiFast(
                        'Scope Of Work'
                    ),
        
                    'page_description' => uiFast(
                        'Services tailored for their dream day'
                    ),
        
                    'saved_events_count' =>
                        count($savedEvents),
        
                    'user_role' => $user_role,
        
                    'logged_in_user' => $user_details,
        
                ], 200);
        
            }
            catch (\Exception $e)
            {
                DB::rollBack();
        
                Log::error(
                    'Save Scope Of Work Error',
                    [
                        'proposal_id' => $proposal_id ?? null,
                        'user_id' => $user->id ?? null,
                        'error' => $e->getMessage(),
                        'line' => $e->getLine(),
                        'file' => $e->getFile()
                    ]
                );
        
                return response()->json([
        
                    'message' => uiFast(
                        'Unable to save scope of work. Please try again.'
                    ),
        
                    'status' => '0',
        
                    'user_role' => $user_role,
        
                    'logged_in_user' => $user_details,
        
                ], 500);
            }
        }
            
            
        public function saveaboutus(Request $request)
            {
            $token = $request->header('Authorization');
        
            $user = $this->getuser($token);
        
            if (!$user)
            {
                return response()->json([
        
                    'message' => uiFast('User not found.'),
        
                    'status' => '0',
        
                    'user_role' => '',
        
                    'logged_in_user' => []
        
                ], 401);
            }
        
            $user_details = [
        
                'name' => $user->name,
        
                'email' => $user->email,
        
                'mobile' => $user->mobile,
        
                'business_name' => $user->business_name
        
            ];
        
            $useraccess = $this->checkeditaccess($token);
        
            $user_role = $useraccess['role'];
        
            /*
            |--------------------------------------------------------------------------
            | Proposal Validation
            |--------------------------------------------------------------------------
            */
        
            if (empty($request->proposal_id))
            {
                return response()->json([
        
                    'message' => uiFast(
                        'Proposal ID is required.'
                    ),
        
                    'status' => '0',
        
                    'user_role' => $user_role,
        
                    'logged_in_user' => $user_details
        
                ], 200);
            }
        
            $proposal = DB::table('client_proposals')
                ->where('id', $request->proposal_id)
                ->first();
        
            if (!$proposal)
            {
                return response()->json([
        
                    'message' => uiFast(
                        'Invalid proposal selected.'
                    ),
        
                    'status' => '0',
        
                    'user_role' => $user_role,
        
                    'logged_in_user' => $user_details
        
                ], 200);
            }
        
            if ($proposal->user_id != $user->id)
            {
                return response()->json([
        
                    'message' => uiFast(
                        'You do not have permission to access this proposal.'
                    ),
        
                    'status' => '0',
        
                    'user_role' => $user_role,
        
                    'logged_in_user' => $user_details
        
                ], 200);
            }
        
            /*
            |--------------------------------------------------------------------------
            | Save About Us
            |--------------------------------------------------------------------------
            */
        
            DB::table('client_proposals')
                ->where('id', $request->proposal_id)
                ->update([
        
                    'planner_message' =>
                        $request->planner_message,
        
                    'current_step' => 4,
        
                    'proposal_status' => 'Completed',
        
                    'updated_at' =>
                        Carbon::now('Asia/Kolkata')
                        ->format('Y-m-d H:i:s')
        
                ]);
        
            return response()->json([
        
                'message' => uiFast(
                    'About us details saved successfully.'
                ),
        
                'status' => '1',
        
                'proposal_id' => $request->proposal_id,
        
                'step_number' => 4,
        
                'total_steps' => 4,
        
                'step_display_text' => uiFast('4/4'),
        
                'page_title' => uiFast('About Us'),
        
                'page_description' => uiFast(
                    'Personal Notes from your Planner'
                ),
        
                'box_heading' => uiFast(
                    'Message to the Couple'
                ),
        
                'is_proposal_completed' => 'yes',
        
                'user_role' => $user_role,
        
                'logged_in_user' => $user_details
        
            ], 200);
        }
        
        
        public function viewproposal_1(Request $request)
