                                    )
                                )
                            )
                    
                    ],
            
                    'wedding_duration_days' =>
                        $proposal->wedding_duration_days
            
                ];
            
                /*
                |--------------------------------------------------------------------------
                | Celebration
                |--------------------------------------------------------------------------
                */
            
                $events = DB::table('proposal_events')
                    ->where('proposal_id', $proposal->id)
                    ->orderBy('day_number')
                    ->orderBy('id')
                    ->get();
            
                $celebration = [];
            
                foreach ($events->groupBy('day_number') as $day => $dayEvents)
                {
                    $eventList = [];
            
                    foreach ($dayEvents as $event)
                    {
                        $eventList[] = [
            
                            'event_name' => $event->event_name,
            
