                }
            
                /*
                |--------------------------------------------------------------------------
                | Scope Of Work
                |--------------------------------------------------------------------------
                */
            
                $scope_of_work = [];
            
                $estimated_total = 0;
            
                foreach ($events as $event)
                {
                    $scopes = DB::table('proposal_scope_items')
