                | Couple Details
                |--------------------------------------------------------------------------
                */
                
                $weddingStyleDisplay = null;

                if (!empty($proposal->custom_wedding_style))
                {
                    $weddingStyleDisplay =
                        $proposal->custom_wedding_style;
                }
                elseif (!empty($proposal->wedding_style))
                {
                    $weddingStyleDisplay =
                        __('dashboard.wedding_styles.'.$proposal->wedding_style);
                }

            
                $couple_details = [
            
