                        $proposal->wedding_duration_days
            
                ];
            
                 /*
                |--------------------------------------------------------------------------
                | Celebration + Scope Of Work Nested Structure
                |--------------------------------------------------------------------------
                */
                
                $events = DB::table('proposal_events')
                    ->where('proposal_id', $proposal->id)
                    ->orderBy('day_number')
                    ->orderBy('id')
                    ->get();
                
                $estimated_total = 0;
                
                $scopeTypeDisplay = [
                
                    'venue'               => uiFast('Venue'),
                    'catering'            => uiFast('Catering'),
                    'decoration'          => uiFast('Decoration'),
