                ];
                
                $venueTypeDisplay = [
                
                    'banquet_hall'  => uiFast('Banquet Hall'),
                    'wedding_lawn'  => uiFast('Wedding Lawn'),
                    'marriage_hall' => uiFast('Marriage Hall')
                
                ];
                
                $celebration = [];
                
                foreach ($events->groupBy('day_number') as $day => $dayEvents)
                {
                    $eventList = [];
                
                    foreach ($dayEvents as $event)
                    {
                        $scopeList = [];
                
                        $scopes = DB::table('proposal_scope_items')
                            ->where('proposal_event_id', $event->id)
