                                )
                                ->pluck('image_path')
                                ->toArray();
                
                            $fullImages = [];
                
                            foreach ($images as $img)
                            {
                                $fullImages[] =
                                    url('/storage/'.$img);
                            }
                
                             $price = 0;

                                /*
                                |--------------------------------------------------------------------------
                                | Catering Calculation
                                |--------------------------------------------------------------------------
                                */
                                if (
                                    $scope->scope_type == 'catering'
                                    &&
                                    !empty($data['meal_types'])
                                    &&
                                    is_array($data['meal_types'])
                                )
                                {
                                    $cateringTotal = 0;
                                
                                    foreach ($data['meal_types'] as $k => $meal)
                                    {
                                        $mealCost =
                                            (float)($meal['meal_cost'] ?? 0);
                                
                                        $headCount =
                                            (float)($meal['head_count'] ?? 0);
                                
                                        $totalCost =
                                            $mealCost * $headCount;
                                
                                        $data['meal_types'][$k]['total_cost'] =
                                            $totalCost;
                                
                                        $cateringTotal += $totalCost;
                                    }
                                
                                    $price = $cateringTotal;
                                
                                    $data['tentative_pricing'] = $price;
                                }
                                else
                                {
                                    if (!empty($data['tentative_pricing']))
                                    {
                                        $price =
                                            (float)$data['tentative_pricing'];
                                    }
                                }
                                
                                $estimated_total += $price;
                
                            if (
                                isset($data['venue_type'])
                            )
                            {
                                $data['venue_type'] = [
                
                                    'value' =>
                                        $data['venue_type'],
                
                                    'display_text' =>
                                        $venueTypeDisplay[
                                            $data['venue_type']
                                        ] ?? null
                                ];
                            }
                
                
                          

                            $scopeList[] = [
                
                                'scope_id' => $scope->id,
                
                                'scope_type' => [
                
                                    'value' =>
                                        $scope->scope_type,
                
                                    'display_text' =>
                                        $scopeTypeDisplay[
                                            $scope->scope_type
                                        ] ?? $scope->scope_type
                                ],
                
                                'details' => $data,
                
                                'tentative_pricing' => $price,
                
                                'images' => $fullImages
                
                            ];
                        }
                
                        $eventList[] = [
                
                            'event_id' => $event->id,
                
                            'event_name' => $event->event_name,
                
                            'event_date' => $event->event_date,
                
                            'event_time' => $event->event_time,
                
                            'scope_of_work' => $scopeList
                
                        ];
                    }
                
                    $celebration[] = [
                
                        'day_number' => (int)$day,
                
