        public function deleteproposal(Request $request)
            {
                $token = $request->header('Authorization');
            
                $user = $this->getuser($token);
            
                if (!$user)
                {
                    return response()->json([
            
                        'message' => uiFast('User not found'),
            
                        'status' => '0',
            
                        'user_role' => "",
            
                        'logged_in_user' => []
            
                    ], 401);
                }
            
                $user_details = [
            
                    'name' => $user->name,
                    'email' => $user->email,
                    'mobile' => $user->mobile,
                    'business_name' => $user->business_name
            
                ];
            
                $useraccess = $this->checkeditaccess($token);
            
                $user_role = $useraccess['role'];
            
                if (empty($request->proposal_id))
                {
                    return response()->json([
            
                        'message' => uiFast(
                            'Proposal ID is required.'
                        ),
            
                        'status' => '0',
            
                        'user_role' => $user_role,
            
                        'logged_in_user' => $user_details
            
                    ], 200);
                }
            
                $proposal = DB::table('client_proposals')
                    ->where('id', $request->proposal_id)
                    ->first();
            
                if (!$proposal)
                {
                    return response()->json([
            
                        'message' => uiFast(
                            'Invalid proposal selected.'
                        ),
            
                        'status' => '0',
            
                        'user_role' => $user_role,
            
                        'logged_in_user' => $user_details
            
                    ], 200);
                }
            
                if ($proposal->user_id != $user->id)
                {
                    return response()->json([
            
                        'message' => uiFast(
                            'You do not have permission to delete this proposal.'
                        ),
            
                        'status' => '0',
            
                        'user_role' => $user_role,
            
                        'logged_in_user' => $user_details
            
                    ], 200);
                }
            
                DB::beginTransaction();
            
                try
                {
                    /*
                    |--------------------------------------------------------------------------
                    | Delete Uploaded Images
                    |--------------------------------------------------------------------------
                    */
            
                    $images = DB::table('proposal_scope_images')
                        ->join(
                            'proposal_scope_items',
                            'proposal_scope_items.id',
                            '=',
                            'proposal_scope_images.proposal_scope_item_id'
                        )
                        ->join(
                            'proposal_events',
                            'proposal_events.id',
                            '=',
                            'proposal_scope_items.proposal_event_id'
                        )
                        ->where(
                            'proposal_events.proposal_id',
                            $proposal->id
                        )
                        ->select(
                            'proposal_scope_images.image_path'
                        )
                        ->get();
            
                    foreach ($images as $image)
                    {
                        $fullPath =
                            '/home/gjymj6oxru2v/planawedding/storage/app/public/'.
                            $image->image_path;
            
                        if (File::exists($fullPath))
                        {
                            File::delete($fullPath);
                        }
                    }
            
                    /*
                    |--------------------------------------------------------------------------
                    | Get Event IDs
                    |--------------------------------------------------------------------------
                    */
            
                    $eventIds = DB::table('proposal_events')
                        ->where(
                            'proposal_id',
                            $proposal->id
                        )
                        ->pluck('id')
                        ->toArray();
            
                    /*
                    |--------------------------------------------------------------------------
                    | Get Scope IDs
                    |--------------------------------------------------------------------------
                    */
            
                    $scopeIds = DB::table('proposal_scope_items')
                        ->whereIn(
                            'proposal_event_id',
                            $eventIds
                        )
                        ->pluck('id')
                        ->toArray();
            
                    /*
                    |--------------------------------------------------------------------------
                    | Delete Child Tables
                    |--------------------------------------------------------------------------
                    */
            
                    DB::table('proposal_scope_images')
                        ->whereIn(
                            'proposal_scope_item_id',
                            $scopeIds
                        )
                        ->delete();
            
                    DB::table('proposal_scope_items')
                        ->whereIn(
                            'proposal_event_id',
                            $eventIds
                        )
                        ->delete();
            
                    DB::table('proposal_events')
