                            'event_time' => $event->event_time
            
                        ];
                    }
                }
                
                
                /*
                |--------------------------------------------------------------------------
                | Celebration + Scope Of Work For Chapter Three
                |--------------------------------------------------------------------------
                */
                
                $estimated_total = 0;
                
                $scopeTypeDisplay = [
                
                    'venue'               => 'Venue',
                    'catering'            => 'Catering',
                    'decoration'          => 'Decoration',
