                    'banquet_hall'  => 'Banquet Hall',
                    'wedding_lawn'  => 'Wedding Lawn',
                    'marriage_hall' => 'Marriage Hall'
                
                ];
                
                $celebration = [];
                
                foreach ($events->groupBy('day_number') as $day => $dayEvents)
                {
                    $eventList = [];
                
