                            'source' => 'paw_leads',
                
                            'purchase_type' => 'wedding',
                
                            'couple_service_category' => null,
                
                            'created_at' => Carbon::now(),
                
                            'updated_at' => Carbon::now()
                
                        ]);
                }
                
                /* Add in leads ends */
                
            
                /*
                |--------------------------------------------------------------------------
                | Update Proposal
                |--------------------------------------------------------------------------
                */
            
                DB::table('client_proposals')
                    ->where('id', $proposal->id)
                    ->update([
            
                        'pdf_path' =>
                            $pdfPath,
            
                        'pdf_generated_at' =>
                            Carbon::now('Asia/Kolkata')
            
                    ]);
            
                /*
                |--------------------------------------------------------------------------
                | Response
                |--------------------------------------------------------------------------
                */
            
                return response()->json([
            
                    'message' =>
                        'PDF generated successfully.',
            
                    'status' =>
                        '1',
            
                    'proposal_id' =>
                        $proposal->id,
            
                    'pdf_url' =>
                        url('/storage/' . $pdfPath),
                        
                        
                     'user_role' => $user_role,

                     'logged_in_user' => $user_details

            
                ], 200);
            
            }  

        public function shareproposal_1(Request $request)
            {
                $token = $request->header('Authorization');
            
                $user = $this->getuser($token);
            
                if (!$user)
                {
                    return response()->json([
            
                        'message' => uiFast('User not found.'),
            
                        'status' => '0',
            
                        'user_role' => '',
            
                        'logged_in_user' => []
            
                    ], 401);
                }
            
                $user_details = [
            
                    'name' => $user->name,
            
                    'email' => $user->email,
            
                    'mobile' => $user->mobile,
            
                    'business_name' => $user->business_name
            
                ];
            
                $useraccess = $this->checkeditaccess($token);
            
                $user_role = $useraccess['role'];
            
                /*
                |--------------------------------------------------------------------------
                | Validate Proposal
                |--------------------------------------------------------------------------
                */
            
                if (empty($request->proposal_id))
                {
                    return response()->json([
            
                        'message' => uiFast('Proposal ID is required.'),
            
                        'status' => '0',
            
                        'user_role' => $user_role,
            
                        'logged_in_user' => $user_details
            
                    ], 200);
                }
            
                $proposal = DB::table('client_proposals')
                    ->where('id', $request->proposal_id)
                    ->first();
            
                if (!$proposal)
                {
                    return response()->json([
            
                        'message' => uiFast('Invalid proposal selected.'),
            
                        'status' => '0',
            
                        'user_role' => $user_role,
            
                        'logged_in_user' => $user_details
            
                    ], 200);
                }
            
                if ($proposal->user_id != $user->id)
                {
                    return response()->json([
            
                        'message' => uiFast(
                            'You do not have permission to access this proposal.'
                        ),
            
                        'status' => '0',
            
                        'user_role' => $user_role,
            
                        'logged_in_user' => $user_details
            
                    ], 200);
                }
            
                /*
                |--------------------------------------------------------------------------
                | Generate Fresh PDF
                |--------------------------------------------------------------------------
                */
            
                $request->merge([
            
                    'proposal_id' => $proposal->id
            
                ]);
            
                $pdfResponse =
                    $this->generateproposalpdf(
                        $request
                    );
            
                $pdfData =
                    $pdfResponse->getData(
                        true
                    );
            
                if (
                    empty($pdfData['status'])
                    ||
                    $pdfData['status'] != '1'
                )
                {
                    return response()->json([
            
                        'message' => uiFast(
                            'Unable to generate proposal PDF.'
                        ),
            
                        'status' => '0',
            
                        'user_role' => $user_role,
            
                        'logged_in_user' => $user_details
            
                    ], 200);
                }
            
                /*
                |--------------------------------------------------------------------------
                | Refresh Proposal
                |--------------------------------------------------------------------------
                */
            
                $proposal = DB::table('client_proposals')
                    ->where('id', $proposal->id)
                    ->first();
            
                $planner = DB::table('users')
                    ->where('id', $proposal->user_id)
                    ->first();
            
                /*
                |--------------------------------------------------------------------------
                | Share Content
                |--------------------------------------------------------------------------
                */
            
                $share_content =
                    "Dear ".
                    $proposal->couple_name.
                    ",\n\n".
                    "Greetings!\n\n".
                    "Please find attached the wedding proposal for your review. ".
                    "We request you to kindly go through the details and feel free ".
                    "to reach out to us should you require any clarification or further information.\n\n".
                    "We look forward to being a part of your special celebration.\n\n".
                    "Happy Wedding!\n\n".
                    "Warm Regards,\n".
                    ($planner->business_name ?? '');
            
                /*
                |--------------------------------------------------------------------------
                | Response
                |--------------------------------------------------------------------------
                */
            
                return response()->json([
            
                    'message' => uiFast(
                        'Proposal share content fetched successfully.'
                    ),
            
                    'status' => '1',
            
                    'proposal_id' => $proposal->id,
            
                    'pdf_url' => $pdfData['pdf_url'],
            
                    'share_content' => $share_content,
            
                    'user_role' => $user_role,
            
                    'logged_in_user' => $user_details
            
                ], 200);
            }


